import { Category, Document, AdminAccount, VisitorActivity, UserProfile } from '../types.ts';
import { GOOGLE_SHEET_ID, APPS_SCRIPT_WEBHOOK_URL } from '../constants.ts';

const KEYS = {
  CATEGORIES: 'sp_categories',
  DOCUMENTS: 'sp_documents',
  STATS: 'sp_stats',
  LOGS: 'sp_logs',
  VISITOR_ACTIVITY: 'sp_visitor_spy_logs',
  ACCOUNTS: 'sp_admin_accounts',
  LAST_SYNC: 'sp_last_sync',
  USER_EMAIL: 'sp_user_identity',
  BANNED_EMAILS: 'sp_banned_list',
  USER_XP: 'sp_user_xp',
  USER_HISTORY: 'sp_user_doc_history',
  SHEET_ROW_COUNT: 'sp_document_total_count'
};

const parseCSV = (csv: string) => {
  const lines = csv.split('\n').filter(line => line.trim() !== '');
  if (lines.length <= 1) return { rows: [], totalCount: 0 };

  // Le nombre total de documents correspond au nombre de lignes moins l'en-tête
  const totalCount = lines.length - 1;

  const rows = lines.slice(1).map((line, index) => {
    const values = line.split(/,(?=(?:(?:[^"]*"){2})*[^"]*$)/).map(v => v.trim().replace(/^"|"$/g, ''));
    return {
      title: values[0] || '',
      url: values[1] || '',
      category: values[2] || '',
      subCategory: values[3] || '',
      date: values[4] || new Date().toISOString(),
      id: `doc-${index}`
    };
  });

  return { rows, totalCount };
};

export const storageService = {
  fetchFromSheets: async (): Promise<{ categories: Category[], documents: Document[], totalCount: number }> => {
    try {
      // Construction de l'URL publique de publication CSV
      const csvUrl = `https://docs.google.com/spreadsheets/d/${GOOGLE_SHEET_ID}/export?format=csv&gid=0`;
      const response = await fetch(csvUrl);
      if (!response.ok) throw new Error('Matrice Polaris injoignable');

      const csvData = await response.text();
      const { rows, totalCount } = parseCSV(csvData);

      const categories: Category[] = [];
      const documents: Document[] = [];
      const categoryMap = new Map<string, string>();

      rows.forEach(row => {
        if (!row.title || !row.url || !row.category) return;

        const mainCatName = row.category.trim().toUpperCase();
        const subCatName = row.subCategory ? row.subCategory.trim().toUpperCase() : null;

        if (!categoryMap.has(mainCatName)) {
          const catId = `cat-${mainCatName.replace(/\s+/g, '-')}`;
          categoryMap.set(mainCatName, catId);
          categories.push({ id: catId, name: mainCatName, parentId: null, icon: '🪐' });
        }

        let currentParentId = categoryMap.get(mainCatName)!;

        if (subCatName) {
          const subKey = `${mainCatName}_${subCatName}`;
          if (!categoryMap.has(subKey)) {
            const subId = `sub-${subKey.replace(/\s+/g, '-')}`;
            categoryMap.set(subKey, subId);
            categories.push({ id: subId, name: subCatName, parentId: currentParentId, icon: '📚' });
          }
          currentParentId = categoryMap.get(subKey)!;
        }

        documents.push({
          id: row.id,
          title: row.title,
          description: `Archive classée en ${mainCatName}${subCatName ? ' > ' + subCatName : ''}`,
          categoryId: currentParentId,
          fileUrl: row.url, 
          fileType: 'pdf',
          tags: [mainCatName],
          downloads: 0,
          dateAdded: row.date,
          size: 'Auto'
        });
      });

      localStorage.setItem(KEYS.DOCUMENTS, JSON.stringify(documents));
      localStorage.setItem(KEYS.CATEGORIES, JSON.stringify(categories));
      localStorage.setItem(KEYS.SHEET_ROW_COUNT, totalCount.toString());
      localStorage.setItem(KEYS.LAST_SYNC, new Date().toISOString());

      return { categories, documents, totalCount };
    } catch (error) {
      return { 
        categories: JSON.parse(localStorage.getItem(KEYS.CATEGORIES) || '[]'), 
        documents: JSON.parse(localStorage.getItem(KEYS.DOCUMENTS) || '[]'),
        totalCount: parseInt(localStorage.getItem(KEYS.SHEET_ROW_COUNT) || '0')
      };
    }
  },

  getDrivePreviewUrl: (url: string): string => {
    if (!url || !url.includes('drive.google.com')) return url;
    const idMatch = url.match(/\/d\/([a-zA-Z0-9_-]+)/) || url.match(/[?&]id=([a-zA-Z0-9_-]+)/);
    return idMatch ? `https://drive.google.com/file/d/${idMatch[1]}/preview` : url;
  },

  getUserXP: (): number => parseInt(localStorage.getItem(KEYS.USER_XP) || '0'),
  addXP: (amount: number): number => {
    const newXP = storageService.getUserXP() + amount;
    localStorage.setItem(KEYS.USER_XP, newXP.toString());
    return newXP;
  },
  getGrade: (xp: number): string => {
    if (xp < 200) return 'Apprenti';
    if (xp < 800) return 'Initié';
    if (xp < 2000) return 'Expert';
    if (xp < 5000) return 'Maître';
    return 'Légende Némésis';
  },

  saveUserEmail: (email: string) => localStorage.setItem(KEYS.USER_EMAIL, email),
  getUserEmail: () => localStorage.getItem(KEYS.USER_EMAIL),

  getBannedEmails: (): string[] => JSON.parse(localStorage.getItem(KEYS.BANNED_EMAILS) || '[]'),
  isEmailBanned: (email: string): boolean => storageService.getBannedEmails().includes(email),

  banEmail: (email: string): void => {
    const banned = storageService.getBannedEmails();
    if (!banned.includes(email)) {
      localStorage.setItem(KEYS.BANNED_EMAILS, JSON.stringify([...banned, email]));
      storageService.addLog('BAN', `Email banni : ${email}`);
    }
  },

  unbanEmail: (email: string): void => {
    const banned = storageService.getBannedEmails();
    const filtered = banned.filter(e => e !== email);
    localStorage.setItem(KEYS.BANNED_EMAILS, JSON.stringify(filtered));
    storageService.addLog('BAN', `Email débanni : ${email}`);
  },

  sendToCloudLog: async (email: string, fileName: string, action: string = 'Téléchargement') => {
    const payload = { email, action, fichier: fileName, timestamp: new Date().toLocaleString('fr-FR') };
    try {
      fetch(APPS_SCRIPT_WEBHOOK_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      });
    } catch (e) {}
  },

  getAccounts: (): AdminAccount[] => {
    const data = localStorage.getItem(KEYS.ACCOUNTS);
    if (!data) {
      const defaults: AdminAccount[] = [
        { id: '0', username: 'Astarté', role: 'SUPER_MASTER', lastLogin: '' },
        { id: '1', username: 'Léon', role: 'MASTER', lastLogin: '' }
      ];
      localStorage.setItem(KEYS.ACCOUNTS, JSON.stringify(defaults));
      return defaults;
    }
    return JSON.parse(data);
  },

  addAccount: (username: string, role: 'SUPER_MASTER' | 'MASTER' | 'EDITOR'): void => {
    const accounts = storageService.getAccounts();
    const newAccount: AdminAccount = {
      id: Date.now().toString(),
      username,
      role,
      lastLogin: new Date().toISOString()
    };
    localStorage.setItem(KEYS.ACCOUNTS, JSON.stringify([...accounts, newAccount]));
  },

  removeAccount: (id: string): void => {
    const accounts = storageService.getAccounts();
    const filtered = accounts.filter(a => a.id !== id);
    localStorage.setItem(KEYS.ACCOUNTS, JSON.stringify(filtered));
  },

  getVisitorActivities: () => JSON.parse(localStorage.getItem(KEYS.VISITOR_ACTIVITY) || '[]'),

  getAdvancedStats: () => {
    const activities: VisitorActivity[] = JSON.parse(localStorage.getItem(KEYS.VISITOR_ACTIVITY) || '[]');
    const docs: Document[] = JSON.parse(localStorage.getItem(KEYS.DOCUMENTS) || '[]');
    const topDocs = [...docs].sort((a, b) => b.downloads - a.downloads).slice(0, 5);
    const uniqueEmails = new Set(activities.filter(a => a.email).map(a => a.email));

    const dailyStats: { [key: string]: number } = {};
    const now = new Date();
    for (let i = 0; i < 7; i++) {
        const d = new Date(now);
        d.setDate(d.getDate() - i);
        dailyStats[d.toLocaleDateString('fr-FR')] = 0;
    }

    activities.forEach(act => {
        const dateStr = act.timestamp.split(' ')[0];
        if (dailyStats.hasOwnProperty(dateStr)) dailyStats[dateStr]++;
    });

    const chartData = Object.keys(dailyStats).map(date => ({ date, downloads: dailyStats[date] })).reverse();
    return { topDocs, totalUniqueUsers: uniqueEmails.size, chartData };
  },

  getLogs: () => JSON.parse(localStorage.getItem(KEYS.LOGS) || '[]'),
  addLog: (action: any, details: string) => {
    const logs = JSON.parse(localStorage.getItem(KEYS.LOGS) || '[]');
    const newLog = { id: Date.now().toString(), action, details, timestamp: new Date().toLocaleString() };
    localStorage.setItem(KEYS.LOGS, JSON.stringify([newLog, ...logs].slice(0, 100)));
  },

  logVisit: (): void => {
    const activities = JSON.parse(localStorage.getItem(KEYS.VISITOR_ACTIVITY) || '[]');
    const newAct = { id: `v-${Date.now()}`, type: 'VISIT', timestamp: new Date().toLocaleString() };
    localStorage.setItem(KEYS.VISITOR_ACTIVITY, JSON.stringify([newAct, ...activities].slice(0, 500)));
  },

  logDownload: (email: string, fileName: string, docId?: string) => {
    const activities = JSON.parse(localStorage.getItem(KEYS.VISITOR_ACTIVITY) || '[]');
    const newAct = { id: `d-${Date.now()}`, type: 'DOWNLOAD', email, fileName, timestamp: new Date().toLocaleString() };
    localStorage.setItem(KEYS.VISITOR_ACTIVITY, JSON.stringify([newAct, ...activities].slice(0, 500)));

    // Historique local
    if (docId) {
      const history = JSON.parse(localStorage.getItem(KEYS.USER_HISTORY) || '[]');
      if (!history.includes(docId)) {
        localStorage.setItem(KEYS.USER_HISTORY, JSON.stringify([...history, docId]));
      }
    }
  },

  getUserHistory: (): string[] => JSON.parse(localStorage.getItem(KEYS.USER_HISTORY) || '[]'),

  incrementDownload: (id: string) => {
    const docs = JSON.parse(localStorage.getItem(KEYS.DOCUMENTS) || '[]');
    const idx = docs.findIndex((d: any) => d.id === id);
    if (idx > -1) {
      docs[idx].downloads += 1;
      localStorage.setItem(KEYS.DOCUMENTS, JSON.stringify(docs));
    }
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import AuroraBackground from './components/AuroraBackground.tsx';
import DocumentCard from './components/DocumentCard.tsx';
import AdminDashboard from './components/AdminDashboard.tsx';
import PDFViewer from './components/PDFViewer.tsx';
import PolarisBrain from './components/PolarisBrain.tsx';
import ExamCountdown from './components/ExamCountdown.tsx';
import { storageService } from './services/storageService.ts';
import { Category, Document, AdminAccount } from './types.ts';

const App: React.FC = () => {
  const [categories, setCategories] = useState<Category[]>([]);
  const [documents, setDocuments] = useState<Document[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [searchQuery, setSearchQuery] = useState('');
  const [navigationPath, setNavigationPath] = useState<Category[]>([]);
  const [isAdminMode, setIsAdminMode] = useState(false);
  const [currentAdmin, setCurrentAdmin] = useState<AdminAccount | null>(null);
  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [adminUsername, setAdminUsername] = useState('');
  const [adminPassword, setAdminPassword] = useState('');
  const [loginError, setLoginError] = useState(false);
  const [isSyncing, setIsSyncing] = useState(true);
  const [viewMode, setViewMode] = useState<'archives' | 'library'>('archives');

  const [userXP, setUserXP] = useState(0);
  const [showEmailModal, setShowEmailModal] = useState(false);
  const [pendingDoc, setPendingDoc] = useState<Document | null>(null);
  const [viewerDoc, setViewerDoc] = useState<Document | null>(null);
  const [userEmail, setUserEmail] = useState('');
  const [emailError, setEmailError] = useState('');

  const syncData = async () => {
    setIsSyncing(true);
    const data = await storageService.fetchFromSheets();
    setCategories(data.categories);
    setDocuments(data.documents);
    setTotalCount(data.totalCount);
    setTimeout(() => setIsSyncing(false), 1000);
  };

  useEffect(() => {
    syncData();
    storageService.logVisit(); 
    setUserXP(storageService.getUserXP());
    const savedEmail = storageService.getUserEmail();
    if (savedEmail) setUserEmail(savedEmail);
  }, []);

  const navigateTo = (cat: Category | null) => {
    setViewMode('archives');
    if (!cat) setNavigationPath([]);
    else setNavigationPath([...navigationPath, cat]);
    setSearchQuery('');
  };

  const goBackTo = (index: number | null) => {
    if (index === null) setNavigationPath([]);
    else setNavigationPath(navigationPath.slice(0, index + 1));
    setSearchQuery('');
  };

  const currentLevelCategories = useMemo(() => {
    const parentId = navigationPath.length > 0 ? navigationPath[navigationPath.length - 1].id : null;
    return categories.filter(c => c.parentId === parentId);
  }, [categories, navigationPath]);

  const displayedDocuments = useMemo(() => {
    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      return documents.filter(d => 
        d.title.toLowerCase().includes(q) || 
        d.description.toLowerCase().includes(q)
      );
    }

    if (viewMode === 'library') {
      const historyIds = storageService.getUserHistory();
      return documents.filter(doc => historyIds.includes(doc.id));
    }

    if (navigationPath.length === 0) return [];
    const lastCatId = navigationPath[navigationPath.length - 1].id;
    return documents.filter(doc => doc.categoryId === lastCatId && doc.fileUrl !== '');
  }, [documents, navigationPath, searchQuery, viewMode]);

  const initiateDownload = (doc: Document) => {
    if (!doc.fileUrl) return;
    setPendingDoc(doc);
    const savedEmail = storageService.getUserEmail();
    if (!savedEmail) setShowEmailModal(true);
    else processDownload(savedEmail, doc);
  };

  const processDownload = (email: string, doc: Document) => {
    if (storageService.isEmailBanned(email)) {
      alert("⚠️ ACCÈS RÉVOQUÉ : Votre identité a été proscrite de la Matrice Polaris.");
      return;
    }
    storageService.logDownload(email, doc.title, doc.id);
    storageService.incrementDownload(doc.id);
    storageService.sendToCloudLog(email, doc.title, 'Téléchargement');

    const newXP = storageService.addXP(10);
    setUserXP(newXP);

    setViewerDoc(doc);
  };

  const handleIdentityConfirm = (e: React.FormEvent) => {
    e.preventDefault();
    if (!userEmail.includes('@')) { setEmailError('Email invalide'); return; }
    if (pendingDoc) {
      storageService.saveUserEmail(userEmail);
      processDownload(userEmail, pendingDoc);
      setShowEmailModal(false);
      setEmailError('');
    }
  };

  const handleAdminLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const accounts = storageService.getAccounts();
    const user = accounts.find(a => a.username.toLowerCase() === adminUsername.toLowerCase());

    let isAuthorized = false;
    if (adminUsername.toLowerCase() === 'astarté' && adminPassword === '2008') {
      isAuthorized = true;
    } 
    else if (adminUsername.toLowerCase() === 'léon' && adminPassword === 'mazedxn7') {
      isAuthorized = true;
    }

    if (isAuthorized && user) {
      setIsAdminMode(true);
      setCurrentAdmin(user);
      setShowAdminLogin(false);
      setLoginError(false);
      setAdminUsername('');
      setAdminPassword('');
      storageService.addLog('AUTH', `Éveil système pour ${user.username}`);
    } else {
      setLoginError(true);
      setTimeout(() => setLoginError(false), 3000);
    }
  };

  const userGrade = storageService.getGrade(userXP);

  return (
    <div className="min-h-screen text-slate-100 font-['Inter'] relative overflow-x-hidden pb-24">
      <AuroraBackground />
      <ExamCountdown />
      <PolarisBrain count={totalCount} />

      {viewerDoc && <PDFViewer doc={viewerDoc} onClose={() => setViewerDoc(null)} />}

      <header className="container mx-auto px-6 py-12 flex flex-col items-center gap-12 relative z-50">
        <div className="w-full flex justify-between items-start max-w-6xl">
