import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { Document, Category, ChatMessage } from '../types.ts';

interface PolarisBrainProps {
  count: number;
  documents: Document[];
  categories: Category[];
}

const PolarisBrain: React.FC<PolarisBrainProps> = ({ count, documents, categories }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    if (isOpen) scrollToBottom();
  }, [messages, isTyping, isOpen]);

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputValue.trim() || isTyping) return;

    const userMessage: ChatMessage = {
      role: 'user',
      text: inputValue,
      timestamp: new Date().toLocaleTimeString()
    };

    setMessages(prev => [...prev, userMessage]);
    setInputValue('');
    setIsTyping(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      // Préparation du contexte des documents pour l'IA
      const docsContext = documents.map(d => `- ${d.title} (ID: ${d.id}, Cat: ${categories.find(c => c.id === d.categoryId)?.name || 'Inconnue'}): ${d.description}`).join('\n');

      const systemInstruction = `Tu es Polaris Brain, l'intelligence artificielle gardienne du Palais Astral SuccessPolaris.
Ton style est futuriste, poli, extrêmement motivant et protecteur envers les élèves.
Ton but : aider les élèves à réussir leurs examens (BAC 2025 notamment) en suggérant les fichiers PDF appropriés parmi notre base de données.
