                placeholder="Transmettre une requête..." 
                className="flex-1 bg-transparent px-4 py-3 text-[11px] font-bold text-white outline-none placeholder-white/20"
              />
              <button 
                type="submit"
                disabled={!inputValue.trim() || isTyping}
                className="w-10 h-10 bg-cyan-500 text-slate-950 rounded-xl flex items-center justify-center hover:bg-white transition-all disabled:opacity-30"
              >
                <i className="fas fa-paper-plane text-xs"></i>
              </button>
            </div>
          </form>
        </div>
      )}
    </>
  );
};

