import { Document, Category, ChatMessage } from '../types.ts';

interface PolarisBrainProps {
  count: number;
  documents: Document[];
  categories: Category[];
}

const PolarisBrain: React.FC<PolarisBrainProps> = ({ count, documents, categories }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Clé API fournie par l'utilisateur
  const OPENROUTER_API_KEY = "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";

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    if (isOpen) scrollToBottom();
  }, [messages, isTyping, isOpen]);

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputValue.trim() || isTyping) return;

    const userMessage: ChatMessage = {
      role: 'user',
      text: inputValue,
      timestamp: new Date().toLocaleTimeString()
    };

    setMessages(prev => [...prev, userMessage]);
    setInputValue('');
    setIsTyping(true);

    try {
      // Préparation du contexte des documents (RAG Light)
      const docsContext = documents.map(d => `- ${d.title} (Cat: ${categories.find(c => c.id === d.categoryId)?.name || 'Général'}): ${d.description}`).join('\n');

      const systemPrompt = `Tu es Polaris Brain, l'assistant intelligent du site SuccessPolaris. 
Ton style est futuriste, poli et extrêmement motivant. Tu es un tuteur pour les élèves préparant le BAC 2025.
Voici la base de données des documents PDF disponibles sur le site :\n${docsContext}\n
RÈGLES CRITIQUES :
1. Si l'utilisateur cherche un cours, suggère le titre exact d'un document de la liste ci-dessus et explique pourquoi il est utile.
2. Encourage toujours l'élève à consulter et "Obtenir" les fichiers PDF pour réussir.
3. Ne mentionne jamais que tu es une IA de DeepSeek ou OpenRouter, tu es la "Conscience Polaris".
4. Tu peux suggérer des parcours d'apprentissage basés sur les titres disponibles.
5. Utilise un vocabulaire lié aux étoiles, à la réussite et à la persévérance.`;

      const response = await fetch("https://openrouter.ai/api/v1/chat/completions", {
        method: "POST",
        headers: {
          "Authorization": `Bearer ${OPENROUTER_API_KEY}`,
          "HTTP-Referer": window.location.origin,
          "X-Title": "SuccessPolaris",
          "Content-Type": "application/json"
        },
        body: JSON.stringify({
          "model": "deepseek/deepseek-r1-0528:free",
          "messages": [
            { "role": "system", "content": systemPrompt },
            ...messages.map(m => ({
              role: m.role === 'model' ? 'assistant' : 'user',
              content: m.text
            })),
            { "role": "user", "content": inputValue }
          ]
        })
      });

      if (!response.ok) throw new Error("Erreur de communication Nexus");

      const data = await response.json();
      const aiText = data.choices[0]?.message?.content || "La Matrice ne répond pas. Veuillez réitérer votre requête.";

      setMessages(prev => [...prev, {
        role: 'model',
        text: aiText,
        timestamp: new Date().toLocaleTimeString()
      }]);
    } catch (error) {
      console.error("AI Error:", error);
      setMessages(prev => [...prev, {
        role: 'model',
        text: "Une perturbation dans la Voie Lactée empêche la transmission. Vérifiez votre connexion.",
        timestamp: new Date().toLocaleTimeString()
      }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <>
      {/* Badge Flottant / Compteur d'Archives */}
      <div className="fixed bottom-6 right-6 z-[7000] animate-in slide-in-from-bottom-10 duration-1000 flex flex-col items-end">
        <button 
          onClick={() => setIsOpen(!isOpen)}
          className="group relative"
        >
          <div className="absolute inset-0 bg-cyan-500/20 blur-xl rounded-full scale-110 opacity-0 group-hover:opacity-100 transition-opacity duration-700"></div>

          <div className={`relative bg-slate-950/80 backdrop-blur-3xl border ${isOpen ? 'border-cyan-400' : 'border-white/10'} px-5 py-3 rounded-[1.5rem] shadow-2xl flex items-center gap-4 transition-all duration-500 transform ${isOpen ? 'scale-90 opacity-0' : 'hover:scale-105'}`}>
             <div className="w-10 h-10 bg-cyan-500/10 border border-cyan-400/30 rounded-xl flex items-center justify-center shadow-neon">
                <i className="fas fa-brain text-cyan-400 text-sm animate-pulse"></i>
             </div>
             <div className="flex flex-col items-start">
                <span className="text-[8px] font-black uppercase text-cyan-400/60 tracking-widest leading-none">Conscience Polaris</span>
                <span className="text-[14px] font-black text-white flex items-baseline gap-1">
                  <span>{count}</span> 
                  <span className="text-[8px] text-white/30 uppercase tracking-tighter">Archives</span>
                </span>
             </div>
             <div className="flex items-center ml-1">
                <span className="w-2 h-2 bg-cyan-500 rounded-full animate-pulse shadow-neon"></span>
             </div>
          </div>
        </button>
      </div>

      {/* Interface de Chat IA */}
      {isOpen && (
        <div className="fixed bottom-6 right-6 w-[380px] h-[550px] max-h-[85vh] z-[8000] bg-slate-950/90 backdrop-blur-3xl border border-white/10 rounded-[2.5rem] shadow-[0_20px_60px_rgba(0,0,0,0.8)] flex flex-col overflow-hidden animate-in slide-in-from-bottom-20 zoom-in-95 duration-500">
