                <i className="fas fa-brain text-slate-950 text-sm"></i>
              </div>
              <div>
                <h3 className="text-white font-black uppercase italic text-[12px] tracking-widest">Polaris Brain</h3>
                <p className="text-[7px] text-cyan-400 font-black uppercase tracking-[0.3em] flex items-center gap-2">
                  <span className="w-1 h-1 bg-cyan-400 rounded-full animate-ping"></span>
                  Noyau DeepSeek Actif
                </p>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="text-white/20 hover:text-white transition-colors">
