import React, { useEffect, useRef } from 'react';

const AuroraBackground: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;
    let mouse = { x: -1000, y: -1000 };
    let stars: Star[] = [];
    const starCount = 600;

    class Star {
      x: number = 0;
      y: number = 0;
      z: number = 0;
      angle: number = 0;
      distance: number = 0;
      speed: number = 0;
      size: number = 0;
      color: string = '';
      opacity: number = 0;
      twinkle: number = 0;

      constructor(canvasWidth: number, canvasHeight: number) {
        this.reset(canvasWidth, canvasHeight, true);
      }

      reset(width: number, height: number, initial = false) {
        this.angle = Math.random() * Math.PI * 2;
        this.distance = Math.random() * (Math.max(width, height) * 0.8);
        this.z = Math.random() * 2; // Profondeur
        this.speed = (Math.random() * 0.0005 + 0.0002) / (this.z + 1);
        this.size = Math.random() * 1.5 + 0.2;
        this.opacity = Math.random();
        this.twinkle = Math.random() * 0.05;

        const colors = ['#ffffff', '#00d4ff', '#7b4dff', '#e6f1ff'];
        this.color = colors[Math.floor(Math.random() * colors.length)];
      }

      update(width: number, height: number) {
        this.angle += this.speed;

        // Position orbitale
        const centerX = width / 2;
        const centerY = height / 2;

        // On simule une légère perspective
        this.x = centerX + Math.cos(this.angle) * this.distance;
        this.y = centerY + Math.sin(this.angle) * this.distance * 0.6; // Ellipse

        // Effet de scintillement
        this.opacity += this.twinkle;
        if (this.opacity > 1 || this.opacity < 0.2) this.twinkle *= -1;

        // Interaction souris : les étoiles s'écartent ou brillent plus
        const dx = this.x - mouse.x;
        const dy = this.y - mouse.y;
        const dist = Math.sqrt(dx * dx + dy * dy);
        if (dist < 150) {
            this.opacity = 1;
        }
      }

      draw(context: CanvasRenderingContext2D) {
        context.globalAlpha = this.opacity;
        context.fillStyle = this.color;

        if (this.size > 1.2) {
            context.shadowBlur = 8;
            context.shadowColor = this.color;
        }

        context.beginPath();
        context.arc(this.x, this.y, this.size, 0, Math.PI * 2);
        context.fill();
        context.shadowBlur = 0;
      }
    }

    const init = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      stars = [];
      for (let i = 0; i < starCount; i++) {
        stars.push(new Star(canvas.width, canvas.height));
      }
    };

    const handleMouseMove = (e: MouseEvent) => {
      mouse.x = e.clientX;
      mouse.y = e.clientY;
    };

    window.addEventListener('resize', init);
    window.addEventListener('mousemove', handleMouseMove);
    init();

    const render = () => {
      // Fond profond avec un léger dégradé radial
      const grad = ctx.createRadialGradient(
        canvas.width / 2, canvas.height / 2, 0,
        canvas.width / 2, canvas.height / 2, canvas.width
      );
      grad.addColorStop(0, '#050b18');
      grad.addColorStop(1, '#020617');

      ctx.globalAlpha = 1;
      ctx.fillStyle = grad;
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Dessiner les étoiles
      stars.forEach(star => {
        star.update(canvas.width, canvas.height);
        star.draw(ctx);
      });

      // Dessiner un voile nébuleux central
      ctx.globalAlpha = 0.05;
      const nebula = ctx.createRadialGradient(
        canvas.width / 2, canvas.height / 2, 0,
        canvas.width / 2, canvas.height / 2, canvas.width * 0.5
      );
      nebula.addColorStop(0, '#00d4ff');
      nebula.addColorStop(1, 'transparent');
      ctx.fillStyle = nebula;
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      animationFrameId = requestAnimationFrame(render);
    };

    render();

    return () => {
      window.removeEventListener('resize', init);
      window.removeEventListener('mousemove', handleMouseMove);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return <canvas ref={canvasRef} className="fixed inset-0 z-[-1] pointer-events-none" />;
};

