import React, { useEffect, useRef } from 'react';

const AuroraBackground: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;
    let stars: Star[] = [];
    const starCount = window.innerWidth < 768 ? 400 : 800; // Plus d'étoiles sur PC

    class Star {
      x: number = 0;
      y: number = 0;
      angle: number = 0;
      distance: number = 0;
      speed: number = 0;
      size: number = 0;
      color: string = '';
      opacity: number = 0;
      twinkle: number = 0;
      glowIntensity: number = 0;

      constructor(w: number, h: number) {
        this.reset(w, h);
      }

      reset(w: number, h: number) {
        this.angle = Math.random() * Math.PI * 2;
        this.distance = Math.random() * (Math.max(w, h) * 0.9);
        this.speed = (Math.random() * 0.0008 + 0.0002);
        this.size = Math.random() * 2 + 0.1;
        this.opacity = Math.random();
        this.twinkle = Math.random() * 0.02 + 0.005;
        this.glowIntensity = Math.random() * 15 + 5;

        const colors = ['#ffffff', '#00d4ff', '#7b4dff', '#b3ffff', '#ffffff'];
        this.color = colors[Math.floor(Math.random() * colors.length)];
      }

      update(w: number, h: number) {
        this.angle += this.speed;

        // Orbite Elliptique pour effet galactique
        const centerX = w / 2;
        const centerY = h / 2;
        this.x = centerX + Math.cos(this.angle) * this.distance;
        this.y = centerY + Math.sin(this.angle) * this.distance * 0.5; // Inclinaison 3D

        // Scintillement
        this.opacity += this.twinkle;
        if (this.opacity > 1 || this.opacity < 0.1) this.twinkle *= -1;
      }

      draw(context: CanvasRenderingContext2D) {
        context.globalAlpha = this.opacity;

        // Effet d'éclat (Glow) pour les étoiles principales
        if (this.size > 1.2) {
            context.shadowBlur = this.glowIntensity;
            context.shadowColor = this.color;
        } else {
            context.shadowBlur = 0;
        }

        context.fillStyle = this.color;
        context.beginPath();
        context.arc(this.x, this.y, this.size, 0, Math.PI * 2);
        context.fill();
      }
    }

    const init = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      stars = [];
      for (let i = 0; i < starCount; i++) {
        stars.push(new Star(canvas.width, canvas.height));
      }
    };

    window.addEventListener('resize', init);
    init();

    const render = () => {
      // Effet de traînée légère (Motion Blur)
      ctx.globalAlpha = 1;
      ctx.fillStyle = '#020617';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Nébuleuse centrale éclatante
      const nebula = ctx.createRadialGradient(
        canvas.width / 2, canvas.height / 2, 0,
        canvas.width / 2, canvas.height / 2, canvas.width * 0.6
      );
      nebula.addColorStop(0, 'rgba(0, 212, 255, 0.08)');
      nebula.addColorStop(0.5, 'rgba(123, 77, 255, 0.03)');
      nebula.addColorStop(1, 'transparent');
      ctx.fillStyle = nebula;
      ctx.globalAlpha = 1;
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      stars.forEach(star => {
        star.update(canvas.width, canvas.height);
        star.draw(ctx);
      });

      animationFrameId = requestAnimationFrame(render);
    };

    render();

    return () => {
      window.removeEventListener('resize', init);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return <canvas ref={canvasRef} className="fixed inset-0 z-[-1] pointer-events-none" style={{ background: '#020617' }} />;
};

