import React, { useEffect, useRef } from 'react';

const AuroraBackground: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;
    let stars: Star[] = [];
    // On augmente drastiquement le nombre d'étoiles pour l'effet "éclatant"
    const starCount = window.innerWidth < 768 ? 500 : 1000;

    class Star {
      x: number = 0;
      y: number = 0;
      angle: number = 0;
      distance: number = 0;
      speed: number = 0;
      size: number = 0;
      color: string = '';
      opacity: number = 0;
      twinkle: number = 0;
      glowSize: number = 0;

      constructor(w: number, h: number) {
        this.reset(w, h);
      }

      reset(w: number, h: number) {
        this.angle = Math.random() * Math.PI * 2;
        // Distribution vers le centre pour l'effet galaxie
        const distBase = Math.random();
        this.distance = Math.pow(distBase, 0.6) * (Math.max(w, h) * 0.8);

        // Vitesse orbitale (plus proche = plus vite)
        this.speed = (0.0005 + Math.random() * 0.001) / (this.distance / 100 + 1);

        this.size = Math.random() * 2.2 + 0.2;
        this.opacity = Math.random();
        this.twinkle = Math.random() * 0.04 + 0.01;
        this.glowSize = Math.random() * 20 + 5;

        const colors = [
          '#ffffff', // Blanc pur
          '#00d4ff', // Cyan Polaris
          '#7b4dff', // Violet
          '#b3ffff', // Cyan clair
          '#f0f9ff'  // Bleu ciel très clair
        ];
        this.color = colors[Math.floor(Math.random() * colors.length)];
      }

      update(w: number, h: number) {
        this.angle += this.speed;

        const centerX = w / 2;
        const centerY = h / 2;

        // Orbite avec une légère oscillation
        const drift = Math.sin(this.angle * 2) * 10;
        this.x = centerX + Math.cos(this.angle) * (this.distance + drift);
        this.y = centerY + Math.sin(this.angle) * (this.distance + drift) * 0.5; // Effet de perspective

        // Effet de scintillement intense
        this.opacity += this.twinkle;
        if (this.opacity > 1 || this.opacity < 0.1) this.twinkle *= -1;
      }

      draw(context: CanvasRenderingContext2D) {
        context.globalAlpha = this.opacity;

        // Éclat intense (Bloom) pour les étoiles de taille moyenne/grande
        if (this.size > 1.0) {
            context.shadowBlur = this.glowSize * this.opacity;
            context.shadowColor = this.color;
        } else {
            context.shadowBlur = 0;
        }

        context.fillStyle = this.color;
        context.beginPath();
        context.arc(this.x, this.y, this.size, 0, Math.PI * 2);
        context.fill();

        // Petit éclat de croix pour les plus brillantes
        if (this.size > 1.8 && this.opacity > 0.8) {
            context.lineWidth = 0.5;
            context.strokeStyle = this.color;
            context.beginPath();
            context.moveTo(this.x - this.size * 2, this.y);
            context.lineTo(this.x + this.size * 2, this.y);
            context.moveTo(this.x, this.y - this.size * 2);
            context.lineTo(this.x, this.y + this.size * 2);
            context.stroke();
        }
      }
    }

    const init = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      stars = [];
      for (let i = 0; i < starCount; i++) {
        stars.push(new Star(canvas.width, canvas.height));
      }
    };

    window.addEventListener('resize', init);
    init();

    const render = () => {
      // Fond sombre mais avec un éclat central
      ctx.globalAlpha = 1;
      ctx.fillStyle = '#01040a';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Nébuleuse centrale lumineuse
      const centerX = canvas.width / 2;
      const centerY = canvas.height / 2;
      const nebula = ctx.createRadialGradient(
        centerX, centerY, 0,
        centerX, centerY, canvas.width * 0.7
      );
      nebula.addColorStop(0, 'rgba(0, 212, 255, 0.12)');
      nebula.addColorStop(0.3, 'rgba(123, 77, 255, 0.05)');
      nebula.addColorStop(0.6, 'rgba(0, 0, 0, 0)');

      ctx.globalAlpha = 1;
      ctx.fillStyle = nebula;
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Dessiner les étoiles avec leur propre contexte de lueur
      stars.forEach(star => {
        star.update(canvas.width, canvas.height);
        star.draw(ctx);
      });

      animationFrameId = requestAnimationFrame(render);
    };

    render();

    return () => {
      window.removeEventListener('resize', init);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return <canvas ref={canvasRef} className="fixed inset-0 z-[-1] pointer-events-none" style={{ background: '#01040a' }} />;
};

export default AuroraBackground;

import React, { useEffect, useRef } from 'react';

const AuroraBackground: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d', { alpha: false }); // Optimisation performance
    if (!ctx) return;

    let animationFrameId: number;
    let stars: Star[] = [];

    // "Milliards" d'étoiles simulées (2000-3000 particules sur canvas = effet visuel massif)
    const starCount = window.innerWidth < 768 ? 1200 : 2500;
    const armCount = 3; // Nombre de bras spiraux

    class Star {
      x: number = 0;
      y: number = 0;
      angle: number = 0;
      radius: number = 0;
      speed: number = 0;
      size: number = 0;
      color: string = '';
      opacity: number = 0;
      twinkle: number = 0;
      spiralOffset: number = 0;
      baseOpacity: number = 0;

      constructor(w: number, h: number) {
        this.reset(w, h);
      }

      reset(w: number, h: number) {
        // Distribution en spirale
        this.radius = Math.random() * (Math.max(w, h) * 0.9);
        const armIndex = Math.floor(Math.random() * armCount);

        // Angle de base + décalage pour former les bras
        const armAngle = (armIndex * (Math.PI * 2)) / armCount;
        const spiralTwist = this.radius * 0.005; // Facteur de torsion de la spirale
        const randomness = (Math.random() - 0.5) * 1.5; // Dispersion autour du bras

        this.angle = armAngle + spiralTwist + randomness;

        // Vitesse orbitale (Loi de Kepler simplifiée : plus lent à l'extérieur)
        this.speed = (0.0002 + Math.random() * 0.0004) * (1 - (this.radius / (Math.max(w, h))));

        this.size = Math.random() * 1.8 + 0.1;
        this.baseOpacity = Math.random() * 0.7 + 0.2;
        this.opacity = this.baseOpacity;
        this.twinkle = Math.random() * 0.02 + 0.005;

        const colors = ['#ffffff', '#00d4ff', '#7b4dff', '#b3ffff', '#ffffff'];
        this.color = colors[Math.floor(Math.random() * colors.length)];
      }

      update(w: number, h: number) {
        this.angle += this.speed;

        const centerX = w / 2;
        const centerY = h / 2;

        // Calcul des coordonnées polaires vers cartésiennes avec inclinaison 3D (0.5 sur Y)
        this.x = centerX + Math.cos(this.angle) * this.radius;
        this.y = centerY + Math.sin(this.angle) * this.radius * 0.45;

        // Scintillement asynchrone
        this.opacity += this.twinkle;
        if (this.opacity > 1 || this.opacity < 0.1) this.twinkle *= -1;
      }

      draw(context: CanvasRenderingContext2D) {
        context.globalAlpha = this.opacity;

        // Effet de halo pour les étoiles brillantes
        if (this.size > 1.3) {
            context.shadowBlur = 10 * this.opacity;
            context.shadowColor = this.color;
        } else {
            context.shadowBlur = 0;
        }

        context.fillStyle = this.color;
        context.beginPath();
        context.arc(this.x, this.y, this.size, 0, Math.PI * 2);
        context.fill();
      }
    }

    const init = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      stars = [];
      for (let i = 0; i < starCount; i++) {
        stars.push(new Star(canvas.width, canvas.height));
      }
    };

    window.addEventListener('resize', init);
    init();

    const render = () => {
      // Fond noir profond
      ctx.globalAlpha = 1;
      ctx.fillStyle = '#01040a';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Cœur galactique ultra-lumineux
      const gradient = ctx.createRadialGradient(
        canvas.width / 2, canvas.height / 2, 0,
        canvas.width / 2, canvas.height / 2, canvas.width * 0.5
      );
      gradient.addColorStop(0, 'rgba(0, 212, 255, 0.15)');
      gradient.addColorStop(0.2, 'rgba(123, 77, 255, 0.05)');
      gradient.addColorStop(0.6, 'rgba(0, 0, 0, 0)');

      ctx.fillStyle = gradient;
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Rendu des étoiles
      stars.forEach(star => {
        star.update(canvas.width, canvas.height);
        star.draw(ctx);
      });

      animationFrameId = requestAnimationFrame(render);
    };

    render();

    return () => {
      window.removeEventListener('resize', init);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return (
    <canvas 
      ref={canvasRef} 
      className="fixed inset-0 z-[-1] pointer-events-none" 
      style={{ background: '#01040a' }} 
    />
  );
};

