import React, { useEffect, useRef } from 'react';

const AuroraBackground: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d', { alpha: false });
    if (!ctx) return;

    let animationFrameId: number;
    let stars: Star[] = [];

    // Simulation de densité massive
    const starCount = window.innerWidth < 768 ? 2000 : 4500;
    const armCount = 4; // 4 bras spiraux majeurs

    class Star {
      x: number = 0;
      y: number = 0;
      angle: number = 0;
      dist: number = 0;
      speed: number = 0;
      size: number = 0;
      color: string = '';
      opacity: number = 0;
      armIndex: number = 0;
      randomOffset: number = 0;

      constructor(w: number, h: number) {
        this.reset(w, h);
      }

      reset(w: number, h: number) {
        this.dist = Math.random() * (Math.max(w, h) * 0.8);
        this.armIndex = Math.floor(Math.random() * armCount);

        // Equation de la spirale logarithmique pour aligner les étoiles "en rang"
        const armAngle = (this.armIndex * (Math.PI * 2)) / armCount;
        const spiralTorsion = this.dist * 0.004; // Plus on s'éloigne, plus ça s'enroule
        this.randomOffset = (Math.random() - 0.5) * 0.4; // Légère dispersion pour le réalisme

        this.angle = armAngle + spiralTorsion + this.randomOffset;

        // Vitesse orbitale : les étoiles suivent une courbe de rotation galactique
        // (plus rapide au centre, stable en périphérie)
        this.speed = (0.0001 + Math.random() * 0.0002) * (150 / (this.dist + 50));

        this.size = Math.random() * 1.2 + 0.1;
        this.opacity = Math.random() * 0.8 + 0.2;

        const colors = ['#ffffff', '#00d4ff', '#7b4dff', '#b3ffff'];
        this.color = colors[Math.floor(Math.random() * colors.length)];
      }

      update(w: number, h: number) {
        this.angle += this.speed;

        const centerX = w / 2;
        const centerY = h / 2;

        // Transformation Polaire -> Cartésienne avec inclinaison 3D (0.45 sur Y)
        this.x = centerX + Math.cos(this.angle) * this.dist;
        this.y = centerY + Math.sin(this.angle) * this.dist * 0.45;
      }

      draw(context: CanvasRenderingContext2D) {
        context.globalAlpha = this.opacity;
        context.fillStyle = this.color;

        // Effet de halo pour les étoiles proches du centre ou grosses
        if (this.dist < 200 || this.size > 1) {
            context.shadowBlur = 5;
            context.shadowColor = this.color;
        } else {
            context.shadowBlur = 0;
        }

        context.beginPath();
        context.arc(this.x, this.y, this.size, 0, Math.PI * 2);
        context.fill();
      }
    }

    const init = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      stars = [];
      for (let i = 0; i < starCount; i++) {
        stars.push(new Star(canvas.width, canvas.height));
      }
    };

    window.addEventListener('resize', init);
    init();

    const render = () => {
      // Fond noir avec très léger feedback pour effet de traînée (motion blur)
      ctx.globalAlpha = 0.8; 
      ctx.fillStyle = '#01040a';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Cœur Galactique (Le Soleil central)
      const centerX = canvas.width / 2;
      const centerY = canvas.height / 2;

      const coreGradient = ctx.createRadialGradient(
        centerX, centerY, 0,
        centerX, centerY, 150
      );
      coreGradient.addColorStop(0, 'rgba(255, 255, 255, 0.4)');
      coreGradient.addColorStop(0.2, 'rgba(0, 212, 255, 0.2)');
      coreGradient.addColorStop(0.5, 'rgba(123, 77, 255, 0.1)');
      coreGradient.addColorStop(1, 'rgba(0, 0, 0, 0)');

      ctx.globalAlpha = 1;
      ctx.fillStyle = coreGradient;
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Rendu des "rangs" d'étoiles
      stars.forEach(star => {
        star.update(canvas.width, canvas.height);
        star.draw(ctx);
      });

      animationFrameId = requestAnimationFrame(render);
    };

    render();

    return () => {
      window.removeEventListener('resize', init);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return (
    <canvas 
      ref={canvasRef} 
      className="fixed inset-0 z-[-1] pointer-events-none" 
      style={{ background: '#01040a' }} 
    />
  );
};

