import React, { useEffect, useRef } from 'react';

const AuroraBackground: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d', { alpha: false });
    if (!ctx) return;

    let animationFrameId: number;
    let stars: Star[] = [];

    // Densité extrême pour simuler des "milliards" sans ralentir le navigateur
    const starCount = window.innerWidth < 768 ? 3000 : 6500;
    // On crée énormément de mini-bras pour supprimer les espaces vides
    const filamentCount = 64; 

    class Star {
      x: number = 0;
      y: number = 0;
      angle: number = 0;
      dist: number = 0;
      initialDist: number = 0;
      speed: number = 0;
      radialSpeed: number = 0;
      size: number = 0;
      color: string = '';
      opacity: number = 0;
      filamentId: number = 0;

      constructor(w: number, h: number) {
        this.reset(w, h, true);
      }

      reset(w: number, h: number, isInitial = false) {
        // Distribution le long des bras pour l'effet de "ligne"
        this.filamentId = Math.floor(Math.random() * filamentCount);

        // Si c'est le reset après être tombé dans le centre, on repart de l'extérieur
        this.dist = isInitial ? Math.random() * Math.max(w, h) : Math.max(w, h) * (0.8 + Math.random() * 0.2);
        this.initialDist = this.dist;

        const armAngle = (this.filamentId * (Math.PI * 2)) / filamentCount;
        // Equation de spirale serrée : pas de dispersion latérale pour garder les "rangs"
        const spiralTorsion = this.dist * 0.005; 
        this.angle = armAngle + spiralTorsion;

        // Vitesse de rotation : plus rapide près du centre (loi du vortex)
        this.speed = 0.002 + (Math.random() * 0.002);

        // Vitesse vers le centre : l'aspiration
        this.radialSpeed = 0.5 + Math.random() * 1.5;

        this.size = Math.random() * 1.5 + 0.2;
        this.opacity = 0; // Apparition progressive

        // Palette de couleurs galactiques
        const rand = Math.random();
        if (rand > 0.8) this.color = '#ffffff'; // Blanc pur
        else if (rand > 0.4) this.color = '#00d4ff'; // Cyan Polaris
        else this.color = '#7b4dff'; // Violet profond
      }

      update(w: number, h: number) {
        // On réduit la distance pour l'aspiration vers le centre
        this.dist -= this.radialSpeed * (1 + (Math.max(w, h) - this.dist) / 500);

        // On augmente l'angle pour la rotation (accélération angulaire près du centre)
        this.angle += this.speed * (200 / (this.dist + 100));

        // Si l'étoile atteint le centre (le soleil), elle renaît aux confins de la galaxie
        if (this.dist < 5) {
          this.reset(w, h, false);
        }

        // Opacité basée sur la distance (plus brillant vers le centre, fondu aux bords)
        this.opacity = Math.min(1, (this.initialDist - this.dist) / 100);

        const centerX = w / 2;
        const centerY = h / 2;

        // Projection 2D avec inclinaison galactique (perspective)
        this.x = centerX + Math.cos(this.angle) * this.dist;
        this.y = centerY + Math.sin(this.angle) * this.dist * 0.5; // Effet d'aplatissement du disque
      }

      draw(context: CanvasRenderingContext2D) {
        context.globalAlpha = this.opacity;
        context.fillStyle = this.color;

        // Effet de halo uniquement pour les flux massifs
        if (this.dist < 300) {
          context.shadowBlur = this.size * 3;
          context.shadowColor = this.color;
        } else {
          context.shadowBlur = 0;
        }

        context.beginPath();
        context.arc(this.x, this.y, this.size, 0, Math.PI * 2);
        context.fill();
      }
    }

    const init = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      stars = [];
      for (let i = 0; i < starCount; i++) {
        stars.push(new Star(canvas.width, canvas.height));
      }
    };

    window.addEventListener('resize', init);
    init();

    const render = () => {
      // Nettoyage avec un noir profond
      ctx.globalAlpha = 1;
      ctx.fillStyle = '#020617';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Le Centre Solaire (L'aspiration lumineuse)
      const centerX = canvas.width / 2;
      const centerY = canvas.height / 2;

      const coreGradient = ctx.createRadialGradient(
        centerX, centerY, 0,
        centerX, centerY, 200
      );
      coreGradient.addColorStop(0, '#ffffff'); // Cœur blanc pur
      coreGradient.addColorStop(0.1, '#00d4ff'); // Halo Cyan
      coreGradient.addColorStop(0.4, 'rgba(123, 77, 255, 0.2)'); // Aura Violette
      coreGradient.addColorStop(1, 'rgba(2, 6, 23, 0)'); // Vers le noir

      ctx.fillStyle = coreGradient;
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Dessin des flux d'étoiles
      stars.forEach(star => {
        star.update(canvas.width, canvas.height);
        star.draw(ctx);
      });

      animationFrameId = requestAnimationFrame(render);
    };

    render();

    return () => {
      window.removeEventListener('resize', init);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return (
    <canvas 
      ref={canvasRef} 
      className="fixed inset-0 z-[-1] pointer-events-none"
    />
  );
};

