  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d', { alpha: false });
    if (!ctx) return;

    let animationFrameId: number;
    let stars: Star[] = [];

    // Haute densité pour un flux continu sans espaces
    const starCount = window.innerWidth < 768 ? 4000 : 9000;
    const arms = 12; // Nombre de bras principaux de la galaxie

    class Star {
      x: number = 0;
      y: number = 0;
      angle: number = 0;
      dist: number = 0;
      initialDist: number = 0;
      speed: number = 0;
      radialSpeed: number = 0;
      size: number = 0;
      color: string = '';
      opacity: number = 0;
      armIndex: number = 0;

      constructor(w: number, h: number) {
        this.reset(w, h, true);
      }

      reset(w: number, h: number, isInitial = false) {
        this.armIndex = Math.floor(Math.random() * arms);

        // Distribution sur l'extérieur pour le flux entrant
        this.dist = isInitial 
          ? Math.random() * Math.max(w, h) 
          : Math.max(w, h) * (0.95 + Math.random() * 0.1);

        this.initialDist = this.dist;

        // Sens trigonométrique : l'angle de base dépend du bras + une torsion spirale
        const armAngle = (this.armIndex * (Math.PI * 2)) / arms;
        const torsion = this.dist * 0.008; 
        this.angle = armAngle + torsion;

        // Vitesse orbitale : plus rapide au centre
        this.speed = 0.005 + Math.random() * 0.01;

        // Vitesse d'aspiration radiale
        this.radialSpeed = 0.8 + Math.random() * 1.5;

        this.size = Math.random() * 1.5 + 0.2;
        this.opacity = 0;

        const rand = Math.random();
        if (rand > 0.85) this.color = '#ffffff'; // Éclat blanc
        else if (rand > 0.4) this.color = '#00d4ff'; // Cyan Polaris
        else this.color = '#7b4dff'; // Violet Astral
      }

      update(w: number, h: number) {
        // Aspiration vers le centre (réduction du rayon)
        // L'aspiration s'accélère à l'approche du noyau
        const gravity = (Math.max(w, h) / (this.dist + 100)) * 0.5;
        this.dist -= (this.radialSpeed + gravity);

        // Rotation en SENS TRIGONOMÉTRIQUE (Anti-horaire)
        // On soustrait à l'angle pour aller vers le haut/gauche sur l'écran
        this.angle -= this.speed * (300 / (this.dist + 150));

        if (this.dist < 5) {
          this.reset(w, h, false);
        }

        // Opacité plus forte au centre
        this.opacity = Math.min(0.9, (this.initialDist - this.dist) / 100);

        const centerX = w / 2;
        const centerY = h / 2;

        // Projection avec légère inclinaison pour l'effet de disque galactique
        this.x = centerX + Math.cos(this.angle) * this.dist;
        this.y = centerY + Math.sin(this.angle) * this.dist * 0.55;
      }

      draw(context: CanvasRenderingContext2D) {
        context.globalAlpha = this.opacity;
        context.fillStyle = this.color;

        // Effet de traînée lumineuse (petit filament)
        context.beginPath();
        context.arc(this.x, this.y, this.size, 0, Math.PI * 2);
        context.fill();
      }
    }

    const init = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      stars = [];
      for (let i = 0; i < starCount; i++) {
        stars.push(new Star(canvas.width, canvas.height));
      }
    };

    window.addEventListener('resize', init);
    init();

    const render = () => {
      // Fond noir profond sans traînée (nettoyage complet)
      ctx.globalAlpha = 1;
      ctx.fillStyle = '#01040a';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      const centerX = canvas.width / 2;
      const centerY = canvas.height / 2;

      // Halo du noyau central
      const coreGradient = ctx.createRadialGradient(centerX, centerY, 0, centerX, centerY, 400);
      coreGradient.addColorStop(0, 'rgba(255, 255, 255, 0.25)');
      coreGradient.addColorStop(0.1, 'rgba(0, 212, 255, 0.15)');
      coreGradient.addColorStop(0.4, 'rgba(123, 77, 255, 0.05)');
      coreGradient.addColorStop(1, 'rgba(1, 4, 10, 0)');
      ctx.fillStyle = coreGradient;
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Dessin des flux stellaires
      stars.forEach(star => {
        star.update(canvas.width, canvas.height);
        star.draw(ctx);
      });

      animationFrameId = requestAnimationFrame(render);
    };

    render();
    return () => {
      window.removeEventListener('resize', init);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return (
    <div className="fixed inset-0 z-[-1] overflow-hidden bg-[#01040a]">
      {/* Canvas Galactique */}
      <canvas ref={canvasRef} className="absolute inset-0 pointer-events-none" />

      {/* Signature ASTARTÉ en Arrière-plan (Immensité lointaine) */}
      <div className="absolute inset-0 flex items-center justify-center pointer-events-none select-none overflow-hidden">
