const AuroraBackground: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d', { alpha: false });
    if (!ctx) return;

    let animationFrameId: number;
    let stars: Star[] = [];

    const isMobile = window.innerWidth < 768;
    const starCount = isMobile ? 15000 : 50000;
    const arms = 8; 

    class Star {
      x: number = 0;
      y: number = 0;
      angle: number = 0;
      dist: number = 0;
      initialDist: number = 0;
      speed: number = 0;
      radialSpeed: number = 0;
      size: number = 0;
      color: string = '';
      opacity: number = 0;

      constructor(w: number, h: number) {
        this.reset(w, h, true);
      }

      reset(w: number, h: number, isInitial = false) {
        this.dist = isInitial 
          ? Math.random() * Math.max(w, h) 
          : Math.max(w, h) * (0.8 + Math.random() * 0.4);

        this.initialDist = this.dist;

        const armIndex = Math.floor(Math.random() * arms);
        const armAngle = (armIndex * (Math.PI * 2)) / arms;
        const torsion = this.dist * 0.005; 
        this.angle = armAngle + torsion + (Math.random() * 0.5);

        this.speed = 0.01 + Math.random() * 0.02;
        this.radialSpeed = 0.5 + Math.random() * 1.5;
        this.size = Math.random() * 1.2 + 0.1;
        this.opacity = 0;

        const rand = Math.random();
        if (rand > 0.9) this.color = '#ffffff'; 
        else if (rand > 0.5) this.color = '#00d4ff'; 
        else this.color = '#7b4dff'; 
      }

      update(w: number, h: number) {
        const gravity = 400 / (this.dist + 10);
        this.dist -= (this.radialSpeed + gravity);
        this.angle -= this.speed * (250 / (this.dist + 100));

        if (this.dist < 2) {
          this.reset(w, h, false);
        }

        this.opacity = Math.min(0.7, (this.initialDist - this.dist) / 100);

        const centerX = w / 2;
        const centerY = h / 2;

        this.x = centerX + Math.cos(this.angle) * this.dist;
        this.y = centerY + Math.sin(this.angle) * this.dist * 0.65;
      }

      draw(context: CanvasRenderingContext2D) {
        if (this.opacity <= 0) return;
        context.globalAlpha = this.opacity;
        context.fillStyle = this.color;
        context.fillRect(this.x, this.y, this.size, this.size);
      }
    }

    const init = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      stars = [];
      for (let i = 0; i < starCount; i++) {
        stars.push(new Star(canvas.width, canvas.height));
      }
    };

    window.addEventListener('resize', init);
    init();

    const render = () => {
      ctx.globalAlpha = 0.3;
      ctx.fillStyle = '#01040a';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      stars.forEach(star => {
        star.update(canvas.width, canvas.height);
        star.draw(ctx);
      });

      animationFrameId = requestAnimationFrame(render);
    };

    render();
    return () => {
      window.removeEventListener('resize', init);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return (
    <div className="fixed inset-0 z-[-1] pointer-events-none select-none overflow-hidden bg-[#01040a]">
      {/* Moteur de rendu galactique */}
      <canvas ref={canvasRef} className="absolute inset-0" />

      {/* Signature Arrière-plan Colossale */}
      <div className="absolute inset-0 flex items-center justify-center">
        <h2 className="text-[28vw] font-black text-white/[0.02] uppercase tracking-[0.4em] italic transform -rotate-12 translate-y-[-5%]">
          ASTARTÉ
        </h2>
      </div>

      {/* Halo d'énergie centrale (Sans le lion pour plus de pureté) */}
      <div className="absolute inset-0 flex items-center justify-center">
        <div className="w-[600px] h-[600px] bg-cyan-500/5 blur-[200px] rounded-full animate-pulse-slow"></div>
      </div>

      {/* Signature Bas (Identité Fondateur) */}
      <div className="absolute bottom-16 left-0 w-full flex flex-col items-center justify-center z-20">
         <div className="h-[2px] w-48 bg-gradient-to-r from-transparent via-cyan-500 to-transparent mb-6"></div>
         <h3 className="text-[20px] md:text-[28px] font-black text-cyan-400 uppercase tracking-[1em] drop-shadow-[0_0_20px_rgba(0,212,255,0.8)] italic animate-glow">
           ASTARTÉ
         </h3>
         <p className="text-[9px] text-white/30 font-black uppercase tracking-[0.6em] mt-4 italic">SuccessPolaris Sovereign</p>
      </div>

      <style>{`
        @keyframes glow {
          0%, 100% { opacity: 0.8; filter: drop-shadow(0 0 5px rgba(0, 212, 255, 0.4)); }
          50% { opacity: 1; filter: drop-shadow(0 0 25px rgba(0, 212, 255, 1)); }
        }
        .animate-glow {
          animation: glow 4s ease-in-out infinite;
        }
        .animate-pulse-slow {
          animation: pulse 6s cubic-bezier(0.4, 0, 0.6, 1) infinite;
        }
      `}</style>
    </div>
  );
};

