      dist: number = 0;
      initialDist: number = 0;
      speed: number = 0;
      radialSpeed: number = 0;
      size: number = 0;
      color: string = '';
      opacity: number = 0;

      constructor(w: number, h: number) {
        this.reset(w, h, true);
      }

      reset(w: number, h: number, isInitial = false) {
        const maxDist = Math.max(w, h);
        this.dist = isInitial 
          ? coreRadius + Math.random() * maxDist
          : maxDist * (0.8 + Math.random() * 0.4);

        this.initialDist = this.dist;

        const armIndex = Math.floor(Math.random() * arms);
        const armAngle = (armIndex * (Math.PI * 2)) / arms;
        const torsion = this.dist * 0.006; 
        this.angle = armAngle + torsion + (Math.random() * 0.4);

        // VITESSE GALACTIQUE
        this.speed = 0.03 + Math.random() * 0.06;
        this.radialSpeed = 1.5 + Math.random() * 4.5;

        // Taille fine pour la brillance sans saturation excessive
        this.size = Math.random() * 1.2 + 0.2;
        this.opacity = 0;

        // PALETTE HARMONIEUSE : BLANC, NEIGE, BEIGE
        const rand = Math.random();
        if (rand > 0.7) {
          this.color = '#ffffff'; // Blanc pur
        } else if (rand > 0.4) {
          this.color = '#fffafa'; // Neige (Snow)
        } else if (rand > 0.1) {
          this.color = '#f5f5dc'; // Beige (Beige classique)
        } else {
          this.color = '#fafafa'; // Blanc cassé / Alabastre
        }
      }

      update(w: number, h: number) {
        const gravity = 1200 / (this.dist + 20);
        this.dist -= (this.radialSpeed + gravity);
        this.angle -= this.speed * (400 / (this.dist + 120));

        // Reset si pénétration dans le noyau
        if (this.dist < coreRadius) {
          this.reset(w, h, false);
        }

        // GESTION DE LA LUMINOSITÉ
        let fade = 1.0;
        const fadeOutEdge = 150; 

        if (this.dist < fadeOutEdge) {
           fade = Math.max(0, (this.dist - coreRadius) / (fadeOutEdge - coreRadius));
        }

        this.opacity = fade * 0.7; // Un peu plus doux pour le mélange de couleurs

        const centerX = w / 2;
        const centerY = h / 2;

        this.x = centerX + Math.cos(this.angle) * this.dist;
        this.y = centerY + Math.sin(this.angle) * this.dist * 0.6;
      }

      draw(context: CanvasRenderingContext2D) {
        if (this.opacity <= 0.05) return;
        context.globalAlpha = this.opacity;
        context.fillStyle = this.color;
        context.fillRect(this.x, this.y, this.size, this.size);
      }
    }

    const init = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      stars = [];
      for (let i = 0; i < starCount; i++) {
        stars.push(new Star(canvas.width, canvas.height));
      }
    };

    window.addEventListener('resize', init);
    init();

    const render = () => {
      ctx.globalCompositeOperation = 'source-over';
      ctx.globalAlpha = 0.22; 
      ctx.fillStyle = '#01040a';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // MODE LIGHTER POUR LA BRILLANCE ÉLÉGANTE
      ctx.globalCompositeOperation = 'lighter';
      stars.forEach(star => {
        star.update(canvas.width, canvas.height);
        star.draw(ctx);
      });

      animationFrameId = requestAnimationFrame(render);
    };

    render();
    return () => {
      window.removeEventListener('resize', init);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return (
    <div className="fixed inset-0 z-[-1] pointer-events-none select-none overflow-hidden bg-[#01040a]">
      {/* Canvas Galactique */}
      <canvas ref={canvasRef} className="absolute inset-0" />

      {/* NOYAU CENTRAL (Horizon des événements) */}
      <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
         <div className="w-[100px] h-[100px] bg-black rounded-full shadow-[0_0_60px_rgba(255,255,255,0.15)] z-10 border border-white/5"></div>
         <div className="absolute w-[400px] h-[400px] bg-white/5 blur-[120px] rounded-full animate-pulse-slow"></div>
      </div>

      {/* Signature Arrière-plan Colossale */}
      <div className="absolute inset-0 flex items-center justify-center">
        <h2 className="text-[28vw] font-black text-white/[0.02] uppercase tracking-[0.4em] italic transform -rotate-12 translate-y-[-5%]">
          ASTARTÉ
        </h2>
      </div>

      {/* Signature Bas (Identité Astarté) */}
      <div className="absolute bottom-16 left-0 w-full flex flex-col items-center justify-center z-20">
         <div className="h-[1px] w-48 bg-gradient-to-r from-transparent via-white/20 to-transparent mb-6"></div>
         <h3 className="text-[20px] md:text-[26px] font-black text-white/60 uppercase tracking-[0.8em] drop-shadow-[0_0_20px_rgba(255,255,255,0.2)] italic animate-glow">
           ASTARTÉ
         </h3>
         <p className="text-[8px] text-white/20 font-black uppercase tracking-[0.5em] mt-4 italic">SuccessPolaris Sovereign</p>
      </div>

      <style>{`
        @keyframes glow {
          0%, 100% { opacity: 0.5; filter: drop-shadow(0 0 10px rgba(255, 255, 255, 0.2)); }
          50% { opacity: 0.8; filter: drop-shadow(0 0 25px rgba(255, 255, 255, 0.4)); }
        }
        @keyframes pulse-slow {
          0%, 100% { transform: scale(1); opacity: 0.1; }
          50% { transform: scale(1.3); opacity: 0.2; }
        }
        .animate-glow {
          animation: glow 4s ease-in-out infinite;
        }
        .animate-pulse-slow {
          animation: pulse-slow 5s ease-in-out infinite;
        }
      `}</style>
    </div>
  );
};

