import React from 'react';
import { Document } from '../types';

interface DocumentCardProps {
  doc: Document;
  onDownload: (doc: Document) => void; 
  onPreview: (doc: Document) => void; 
}

const DocumentCard: React.FC<DocumentCardProps> = ({ doc, onDownload, onPreview }) => {
  const getFileIcon = (type: string) => {
    switch(type) {
      case 'pdf': return '📕';
      case 'docx': return '📘';
      default: return '📄';
    }
  };

  const isNew = () => {
    try {
      const docDate = new Date(doc.dateAdded);
      const now = new Date();
      const diffTime = Math.abs(now.getTime() - docDate.getTime());
      const diffHours = diffTime / (1000 * 60 * 60);
      return diffHours <= 48;
    } catch (e) { return false; }
  };

  return (
    <div className="group relative bg-white/[0.03] backdrop-blur-xl border border-white/5 rounded-[2rem] p-6 hover:border-white/20 transition-all duration-500 overflow-hidden flex flex-col justify-between shadow-xl">
      <div className="absolute -top-16 -right-16 w-32 h-32 bg-white/5 rounded-full blur-[40px] group-hover:bg-white/10 transition-all duration-700"></div>

