import React, { useEffect, useRef } from 'react';

const AuroraBackground: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d', { alpha: false });
    if (!ctx) return;

    let animationFrameId: number;
    let stars: Star[] = [];

    const isMobile = window.innerWidth < 768;
    const starCount = isMobile ? 8000 : 25000; // Un peu moins d'étoiles pour laisser respirer la nébuleuse
    const arms = 5; 
    const coreRadius = 40;

    class Star {
      x: number = 0;
      y: number = 0;
      angle: number = 0;
      dist: number = 0;
      speed: number = 0;
      size: number = 0;
      color: string = '';
      opacity: number = 0;
      twinkleSpeed: number = 0;

      constructor(w: number, h: number) {
        this.reset(w, h, true);
      }

      reset(w: number, h: number, isInitial = false) {
        const maxDist = Math.max(w, h);
        this.dist = isInitial 
          ? Math.random() * maxDist
          : maxDist * 0.8;

        const armIndex = Math.floor(Math.random() * arms);
        const armAngle = (armIndex * (Math.PI * 2)) / arms;
        this.angle = armAngle + (this.dist * 0.003) + (Math.random() * 0.5);

        this.speed = 0.02 + Math.random() * 0.04;
        this.size = Math.random() * 1.5 + 0.3;
        this.twinkleSpeed = Math.random() * 0.05;

        // Palette Chaleureuse : Or, Pêche, Rose, Blanc
        const rand = Math.random();
        if (rand > 0.8) this.color = '#ffcc33'; // Or
        else if (rand > 0.6) this.color = '#ffdab9'; // Pêche
        else if (rand > 0.4) this.color = '#ffb7c5'; // Rose
        else this.color = '#ffffff'; // Blanc
      }

      update(w: number, h: number) {
        this.dist -= (1.5 + (1000 / (this.dist + 10)));
        this.angle -= this.speed * (300 / (this.dist + 100));

        if (this.dist < coreRadius) {
          this.reset(w, h, false);
        }

        const pulse = Math.sin(Date.now() * this.twinkleSpeed) * 0.2 + 0.8;
        this.opacity = (Math.min(1, this.dist / 300)) * pulse;

        const centerX = w / 2;
        const centerY = h / 2;
        this.x = centerX + Math.cos(this.angle) * this.dist;
        this.y = centerY + Math.sin(this.angle) * this.dist * 0.6;
      }

      draw(context: CanvasRenderingContext2D) {
        context.globalAlpha = this.opacity * 0.6;
        context.fillStyle = this.color;
        context.beginPath();
        context.arc(this.x, this.y, this.size, 0, Math.PI * 2);
        context.fill();
      }
    }

    const init = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      stars = [];
      for (let i = 0; i < starCount; i++) {
        stars.push(new Star(canvas.width, canvas.height));
      }
    };

    window.addEventListener('resize', init);
    init();

    const render = () => {
      ctx.globalCompositeOperation = 'source-over';
      ctx.fillStyle = '#050208';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Effet de nébuleuse centrale
      const gradient = ctx.createRadialGradient(
        canvas.width/2, canvas.height/2, 0,
        canvas.width/2, canvas.height/2, canvas.width/1.5
      );
      gradient.addColorStop(0, 'rgba(80, 20, 100, 0.15)');
      gradient.addColorStop(0.5, 'rgba(40, 10, 50, 0.05)');
      gradient.addColorStop(1, 'transparent');
      ctx.fillStyle = gradient;
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      ctx.globalCompositeOperation = 'lighter';
      stars.forEach(star => {
        star.update(canvas.width, canvas.height);
        star.draw(ctx);
      });

      animationFrameId = requestAnimationFrame(render);
    };

    render();
    return () => {
      window.removeEventListener('resize', init);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return (
    <div className="fixed inset-0 z-[-1] pointer-events-none select-none overflow-hidden bg-[#050208]">
      <canvas ref={canvasRef} className="absolute inset-0" />

      {/* Glow Solaire Chaleureux */}
      <div className="absolute inset-0 flex items-center justify-center opacity-30">
         <div className="w-[300px] h-[300px] bg-amber-500/20 blur-[150px] rounded-full animate-pulse-slow"></div>
         <div className="absolute w-[600px] h-[400px] bg-pink-500/10 blur-[180px] rounded-full rotate-45 animate-drift"></div>
      </div>

      <style>{`
        @keyframes drift {
          0%, 100% { transform: translate(-5%, -5%) rotate(45deg); }
          50% { transform: translate(5%, 5%) rotate(50deg); }
        }
        .animate-drift { animation: drift 20s ease-in-out infinite; }
        .animate-pulse-slow { animation: pulse 8s ease-in-out infinite; }
      `}</style>
    </div>
  );
};

