import React, { useState, useEffect, useMemo } from 'react';
import AuroraBackground from './components/AuroraBackground.tsx';
import DocumentCard from './components/DocumentCard.tsx';
import AdminDashboard from './components/AdminDashboard.tsx';
import PDFViewer from './components/PDFViewer.tsx';
import PolarisBrain from './components/PolarisBrain.tsx';
import ExamCountdown from './components/ExamCountdown.tsx';
import { storageService } from './services/storageService.ts';
import { Category, Document, AdminAccount } from './types.ts';

const App: React.FC = () => {
  const [categories, setCategories] = useState<Category[]>([]);
  const [documents, setDocuments] = useState<Document[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [searchQuery, setSearchQuery] = useState('');
  const [navigationPath, setNavigationPath] = useState<Category[]>([]);
  const [isAdminMode, setIsAdminMode] = useState(false);
  const [currentAdmin, setCurrentAdmin] = useState<AdminAccount | null>(null);
  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [adminUsername, setAdminUsername] = useState('');
  const [adminPassword, setAdminPassword] = useState('');
  const [loginError, setLoginError] = useState(false);
  const [isSyncing, setIsSyncing] = useState(true);
  const [viewMode, setViewMode] = useState<'archives' | 'library'>('archives');

  const [userXP, setUserXP] = useState(0);
  const [showEmailModal, setShowEmailModal] = useState(false);
  const [pendingDoc, setPendingDoc] = useState<Document | null>(null);
  const [viewerDoc, setViewerDoc] = useState<Document | null>(null);
  const [userEmail, setUserEmail] = useState('');

  const syncDocs = async () => {
    setIsSyncing(true);
    try {
      const data = await storageService.fetchFromSheets();
      if (data.documents.length > 0) {
        setCategories(data.categories);
        setDocuments(data.documents);
      }
      const count = await storageService.chargerCompteur();
      if (count !== undefined) setTotalCount(count);
    } catch (err) { console.error("Synchro échouée:", err); } 
    finally { setIsSyncing(false); }
  };

  useEffect(() => {
    syncDocs();
    storageService.logVisit(); 
    setUserXP(storageService.getUserXP());
    const savedEmail = storageService.getUserEmail();
    if (savedEmail) setUserEmail(savedEmail);
  }, []);

  const handlePreview = (doc: Document) => {
    storageService.logPreview(storageService.getUserEmail(), doc.title);
    setViewerDoc(doc);
  };

  const handleObtain = (doc: Document) => {
    setPendingDoc(doc);
    const savedEmail = storageService.getUserEmail();
    if (!savedEmail) setShowEmailModal(true);
    else processFullAccess(savedEmail, doc);
  };

  const processFullAccess = (email: string, doc: Document) => {
    if (storageService.isEmailBanned(email)) return alert("Accès Révoqué.");
    storageService.logDownload(email, doc.title, doc.id);
    storageService.incrementDownload(doc.id);
    setUserXP(storageService.addXP(25));
    setViewerDoc(doc);
  };

  const handleIdentityConfirm = (e: React.FormEvent) => {
    e.preventDefault();
    if (pendingDoc && userEmail.includes('@')) {
      storageService.saveUserEmail(userEmail);
      processFullAccess(userEmail, pendingDoc);
      setShowEmailModal(false);
    }
  };

  const navigateTo = (cat: Category | null) => {
    setViewMode('archives');
    setNavigationPath(cat ? [...navigationPath, cat] : []);
    setSearchQuery('');
  };

  const currentLevelCategories = useMemo(() => {
    const parentId = navigationPath.length > 0 ? navigationPath[navigationPath.length - 1].id : null;
    return categories.filter(c => c.parentId === parentId);
  }, [categories, navigationPath]);

  const displayedDocuments = useMemo(() => {
    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      return documents.filter(d => d.title.toLowerCase().includes(q));
    }
    if (viewMode === 'library') {
      const history = storageService.getUserHistory();
      return documents.filter(doc => history.includes(doc.id));
    }
    if (navigationPath.length === 0) return [];
    const lastCatId = navigationPath[navigationPath.length - 1].id;
    return documents.filter(doc => doc.categoryId === lastCatId);
  }, [documents, navigationPath, searchQuery, viewMode]);

  return (
    <div className="min-h-screen text-amber-50 selection:bg-amber-500/30">
      <AuroraBackground />
      <ExamCountdown />
      <PolarisBrain count={totalCount} documents={documents} categories={categories} />
      {viewerDoc && <PDFViewer doc={viewerDoc} onClose={() => setViewerDoc(null)} />}

      <header className="container mx-auto px-6 py-16 flex flex-col items-center gap-12 relative z-50">
        <div className="w-full flex flex-col md:flex-row justify-between items-center gap-8 max-w-6xl">
           <div className="flex flex-col items-center gap-2 cursor-pointer group" onClick={() => navigateTo(null)}>
              <div className="w-16 h-16 bg-gradient-to-br from-amber-400/20 to-orange-500/5 backdrop-blur-2xl border border-amber-500/20 rounded-[2rem] flex items-center justify-center shadow-[0_0_30px_rgba(255,191,0,0.1)] group-hover:scale-105 transition-all duration-500">
                 <i className="fas fa-sun text-amber-400 text-2xl group-hover:rotate-90 transition-transform duration-1000"></i>
              </div>
              <h1 className="text-2xl font-black tracking-widest text-white uppercase italic">
                Success<span className="text-amber-400">Polaris</span>
              </h1>
           </div>

           <div className="flex items-center gap-4">
              <div className="bg-white/5 backdrop-blur-2xl border border-white/10 p-4 rounded-[1.5rem] flex items-center gap-4 shadow-xl">
                 <div className="w-10 h-10 rounded-xl bg-amber-500/10 flex items-center justify-center border border-amber-500/20">
                    <i className="fas fa-leaf text-amber-400 text-sm"></i>
                 </div>
                 <div className="flex flex-col">
                    <p className="text-[7px] font-black uppercase text-amber-500/60 tracking-widest">Savoir Actif</p>
                    <p className="text-[14px] font-black text-white">{totalCount} items</p>
                 </div>
              </div>
           </div>
        </div>

        <div className="w-full max-w-xl relative">
           <div className="relative flex items-center bg-white/5 backdrop-blur-2xl border border-white/10 rounded-[2rem] p-1.5 focus-within:border-amber-500/40 transition-all shadow-2xl">
              <i className="fas fa-search text-amber-200/20 ml-6"></i>
              <input 
                type="text" 
                placeholder="Rechercher une étincelle de savoir..." 
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="flex-1 bg-transparent px-5 py-4 text-[14px] outline-none font-medium text-white placeholder-amber-100/10" 
              />
           </div>
        </div>
      </header>

      <main className="container mx-auto px-6 lg:px-20 pb-32">
        {isAdminMode ? (
          <AdminDashboard categories={categories} documents={documents} currentAdmin={currentAdmin} onRefresh={syncDocs} />
        ) : (
          <div className="space-y-12">
            {!searchQuery && (
              <nav className="flex items-center gap-3 overflow-x-auto no-scrollbar py-2">
                <button onClick={() => { setViewMode('archives'); setNavigationPath([]); }} className={`px-8 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${viewMode === 'archives' && navigationPath.length === 0 ? 'bg-amber-400 text-black shadow-lg shadow-amber-500/20' : 'bg-white/5 text-white/40 hover:text-white'}`}>Secteurs</button>
                <button onClick={() => setViewMode('library')} className={`px-8 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${viewMode === 'library' ? 'bg-amber-400 text-black shadow-lg' : 'bg-white/5 text-white/40 hover:text-white'}`}>Ma Bibliothèque</button>
                {navigationPath.map((cat, i) => (
                  <button key={cat.id} onClick={() => setNavigationPath(navigationPath.slice(0, i + 1))} className="px-6 py-3 rounded-2xl bg-amber-400/10 border border-amber-400/20 text-amber-400 text-[10px] font-black uppercase tracking-widest whitespace-nowrap">{cat.name}</button>
                ))}
              </nav>
            )}

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
              {viewMode === 'archives' && !searchQuery && currentLevelCategories.length > 0 && (
                <div className="lg:col-span-3 grid grid-cols-1 gap-4">
                  {currentLevelCategories.map(cat => (
                    <button key={cat.id} onClick={() => navigateTo(cat)} className="w-full flex items-center justify-between p-6 bg-white/5 border border-white/10 rounded-3xl group hover:bg-amber-400 hover:text-black transition-all duration-500">
                      <span className="text-[11px] font-black uppercase tracking-widest">{cat.name}</span>
                      <i className="fas fa-chevron-right text-[10px] opacity-20 group-hover:opacity-100"></i>
                    </button>
                  ))}
                </div>
              )}
              <div className={`${(searchQuery || viewMode === 'library' || currentLevelCategories.length === 0) ? 'lg:col-span-12' : 'lg:col-span-9'} grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-3 gap-8`}>
                {displayedDocuments.map(doc => (
                  <DocumentCard key={doc.id} doc={doc} onPreview={handlePreview} onDownload={handleObtain} />
                ))}
              </div>
            </div>
          </div>
        )}
      </main>

      <footer className="fixed bottom-0 left-0 w-full py-6 px-12 bg-[#050208]/80 backdrop-blur-3xl border-t border-white/5 flex items-center justify-between z-[1000]">
        <p className="text-[8px] text-amber-200/20 font-black uppercase tracking-[0.5em]">POLARIS SANCTUAIRE // V2.5.0 LUMINA</p>
        <button onClick={() => setShowAdminLogin(true)} className="text-[8px] text-amber-400/40 font-black uppercase tracking-widest hover:text-amber-400 transition-colors italic">Souveraineté Astarté Léon</button>
      </footer>

      {showEmailModal && (
        <div className="fixed inset-0 z-[9000] flex items-center justify-center bg-black/95 p-6">
          <div className="max-w-md w-full p-12 bg-white/5 border border-amber-500/20 rounded-[3rem] text-center shadow-2xl backdrop-blur-3xl">
            <h3 className="text-xl font-black text-white uppercase italic mb-4">Initialisation du Lien</h3>
            <p className="text-[10px] text-amber-100/40 uppercase font-black mb-10 leading-relaxed">Confirmez votre identité pour puiser dans le puits de lumière Polaris.</p>
            <form onSubmit={handleIdentityConfirm} className="space-y-6">
              <input type="email" required placeholder="votre-email@nexus.com" value={userEmail} onChange={e => setUserEmail(e.target.value)} className="w-full bg-black/40 border border-white/10 rounded-2xl px-8 py-5 text-white text-center font-bold outline-none focus:border-amber-400" />
              <button type="submit" className="w-full bg-amber-400 text-black font-black py-5 rounded-2xl uppercase text-[11px] tracking-widest shadow-xl hover:bg-amber-300 transition-all">Débloquer l'Archive</button>
            </form>
          </div>
        </div>
      )}

      {showAdminLogin && (
        <div className="fixed inset-0 z-[10000] flex items-center justify-center bg-black/95 p-6">
          <div className="max-w-sm w-full p-12 bg-white/5 border border-amber-500/20 rounded-[3rem] text-center">
            <button onClick={() => setShowAdminLogin(false)} className="absolute top-10 right-10 text-white/20 hover:text-white text-2xl">×</button>
            <h3 className="text-lg font-black text-amber-400 uppercase italic tracking-widest mb-10">Terminal Racine</h3>
            <form onSubmit={(e) => { e.preventDefault(); if(adminUsername==='mazedxn7' && adminPassword==='léon') setIsAdminMode(true); else setLoginError(true); }} className="space-y-6">
              <input type="text" placeholder="Utilisateur" value={adminUsername} onChange={e => setAdminUsername(e.target.value)} className="w-full bg-black/40 border border-white/10 rounded-2xl px-8 py-5 text-white text-center font-black outline-none" />
              <input type="password" placeholder="Clé de Passe" value={adminPassword} onChange={e => setAdminPassword(e.target.value)} className="w-full bg-black/40 border border-white/10 rounded-2xl px-8 py-5 text-white text-center font-black outline-none" />
              {loginError && <p className="text-red-400 text-[10px] font-black uppercase">Clé d'Accès Invalide</p>}
              <button type="submit" className="w-full bg-white text-black font-black py-5 rounded-2xl uppercase tracking-widest">Connecter</button>
