  const [viewerDoc, setViewerDoc] = useState<Document | null>(null);
  const [userEmail, setUserEmail] = useState('');

  const syncDocs = async () => {
    setIsSyncing(true);
    try {
      const data = await storageService.fetchFromSheets();
      let docsCount = 0;

      if (data.documents.length > 0) {
        setCategories(data.categories);
        setDocuments(data.documents);
        docsCount = data.documents.length;
      }

      const externalCount = await storageService.chargerCompteur();
      // Si le compteur externe échoue ou renvoie 0 alors qu'on a des documents, on utilise docsCount
      setTotalCount(externalCount > 0 ? externalCount : docsCount);

    } catch (err) { 
      console.error("Synchro échouée:", err); 
    } 
    finally { 
