import React, { useState, useRef, useEffect } from 'react';
import { Document, Category, ChatMessage } from '../types.ts';
import { aiService, AIProviderResponse } from '../services/aiService.ts';

interface PolarisBrainProps {
  count: number;
  documents: Document[];
  categories: Category[];
}

const PolarisBrain: React.FC<PolarisBrainProps> = ({ count, documents, categories }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [lastError, setLastError] = useState<boolean>(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    if (isOpen) scrollToBottom();
  }, [messages, isTyping, isOpen]);

  const renderFormattedText = (text: string) => {
    let formatted = text
      .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
      .replace(/\*(.*?)\*/g, '<em>$1</em>')
      .replace(/__(.*?)__/g, '<u>$1</u>')
      .replace(/\n/g, '<br/>');

    return <div dangerouslySetInnerHTML={{ __html: formatted }} />;
  };

  const handleSendMessage = async (e?: React.FormEvent, retryText?: string) => {
    if (e) e.preventDefault();
    const textToSend = retryText || inputValue;
    if (!textToSend.trim() || isTyping) return;

    setLastError(false);
    if (!retryText) {
      const userMessage: ChatMessage = {
        role: 'user',
        text: textToSend,
        timestamp: new Date().toLocaleTimeString()
      };
      setMessages(prev => [...prev, userMessage]);
      setInputValue('');
    }

    setIsTyping(true);

    try {
      const currentMessages = retryText ? messages : [...messages, { role: 'user', text: textToSend, timestamp: '' } as ChatMessage];
      const response: AIProviderResponse = await aiService.processMessage(currentMessages, documents);

      if (response.text) {
        setMessages(prev => [...prev, {
          role: 'model',
          text: response.text.replace(/<think>[\s\S]*?<\/think>/gi, '').trim(),
          timestamp: new Date().toLocaleTimeString()
        }]);
      }
    } catch (error) {
      setLastError(true);
      setMessages(prev => [...prev, {
        role: 'model',
        text: "Désolé, une instabilité temporaire dans le Nexus m'empêche de répondre. Veux-tu réessayer ?",
        timestamp: new Date().toLocaleTimeString()
      }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <>
      <div className="fixed bottom-6 right-6 z-[7000] flex flex-col items-end">
        <button onClick={() => setIsOpen(!isOpen)} className="group relative">
          <div className="absolute inset-0 bg-cyan-500/20 blur-xl rounded-full scale-110 opacity-0 group-hover:opacity-100 transition-opacity duration-700"></div>
          <div className={`relative bg-slate-950/80 backdrop-blur-3xl border ${isOpen ? 'border-cyan-400' : 'border-white/10'} px-5 py-3 rounded-[1.5rem] shadow-2xl flex items-center gap-4 transition-all duration-500`}>
             <div className="w-10 h-10 bg-cyan-500/10 border border-cyan-400/30 rounded-xl flex items-center justify-center shadow-neon">
                <i className="fas fa-brain text-cyan-400 text-sm animate-pulse"></i>
             </div>
             <div className="flex flex-col items-start text-left">
                <span className="text-[8px] font-black uppercase text-cyan-400/60 tracking-widest leading-none">Polaris Brain</span>
                <span className="text-[14px] font-black text-white">Assistant Virtuel</span>
             </div>
          </div>
        </button>
      </div>

      {isOpen && (
        <div className="fixed bottom-0 right-0 w-full sm:bottom-6 sm:right-6 sm:w-[380px] h-[100dvh] sm:h-[550px] max-h-[100dvh] sm:max-h-[85vh] z-[8000] bg-slate-950 sm:bg-slate-950/90 backdrop-blur-3xl border-t sm:border border-white/10 sm:rounded-[2.5rem] shadow-[0_20px_60px_rgba(0,0,0,0.8)] flex flex-col overflow-hidden animate-in slide-in-from-bottom-20 duration-500">

          <div className="bg-slate-900/50 p-6 border-b border-white/5 flex items-center justify-between">
            <div className="flex items-center gap-4">
              <div className="w-10 h-10 bg-white/5 border border-white/10 rounded-xl flex items-center justify-center">
                <i className="fas fa-graduation-cap text-cyan-400 text-sm"></i>
              </div>
              <div>
                <h3 className="text-white font-black uppercase text-[12px] tracking-widest">Polaris Brain</h3>
                <p className="text-[7px] text-white/30 font-black uppercase tracking-[0.3em]">IA Core Alpha</p>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="text-white/20 hover:text-white transition-colors p-2">
              <i className="fas fa-times text-xl"></i>
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-6 space-y-6 scroll-smooth custom-scrollbar">
            {messages.length === 0 && (
              <div className="h-full flex flex-col items-center justify-center text-center space-y-4 px-4">
                <p className="text-[11px] text-white/50 font-medium leading-relaxed uppercase tracking-wider">
                  Bonjour ! Je suis ton assistant **Polaris Brain**.<br/>Mes senseurs sont actifs. Comment puis-je t'aider ?
                </p>
              </div>
            )}

            {messages.map((msg, idx) => (
              <div key={idx} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'} animate-in fade-in slide-in-from-bottom-2`}>
                <div className={`max-w-[90%] p-4 rounded-[1.5rem] text-[12px] leading-relaxed shadow-lg break-words ${
                  msg.role === 'user' 
                  ? 'bg-cyan-500 text-slate-950 font-bold rounded-tr-none' 
                  : 'bg-white/5 border border-white/10 text-white/90 rounded-tl-none'
                }`}>
                  {renderFormattedText(msg.text)}
                  {idx === messages.length - 1 && lastError && msg.role === 'model' && (
                    <button 
                      onClick={() => handleSendMessage(undefined, messages[messages.length-2]?.text)}
                      className="mt-3 block w-full py-2 bg-cyan-400/10 border border-cyan-400/30 rounded-xl text-cyan-400 text-[9px] font-black uppercase tracking-widest hover:bg-cyan-400/20 transition-all"
                    >
                      <i className="fas fa-redo mr-2"></i> Relancer le Flux
                    </button>
                  )}
                </div>
                <span className="text-[7px] text-white/20 font-bold mt-1 px-2">{msg.timestamp}</span>
              </div>
            ))}

            {isTyping && (
              <div className="flex items-center gap-3">
                <div className="flex gap-1">
                  <div className="w-1.5 h-1.5 bg-cyan-400 rounded-full animate-bounce"></div>
                  <div className="w-1.5 h-1.5 bg-cyan-400 rounded-full animate-bounce" style={{animationDelay:'150ms'}}></div>
                  <div className="w-1.5 h-1.5 bg-cyan-400 rounded-full animate-bounce" style={{animationDelay:'300ms'}}></div>
                </div>
                <span className="text-[7px] text-white/20 uppercase font-black tracking-widest italic">Synchronisation...</span>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>

          <form onSubmit={handleSendMessage} className="p-4 sm:p-6 bg-black/40 border-t border-white/5">
            <div className="flex items-center bg-white/5 border border-white/10 rounded-2xl p-1.5 focus-within:border-cyan-500/50 transition-all">
              <input 
                type="text" 
                value={inputValue}
                onChange={e => setInputValue(e.target.value)}
                placeholder="Pose ta question ici..." 
                className="flex-1 bg-transparent px-4 py-3 text-[12px] font-medium text-white outline-none"
              />
              <button 
                type="submit"
                disabled={!inputValue.trim() || isTyping}
                className="w-10 h-10 bg-cyan-500 text-slate-950 rounded-xl flex items-center justify-center disabled:opacity-30 transition-all hover:scale-105 active:scale-95 shadow-neon"
              >
                <i className="fas fa-arrow-up text-xs"></i>
              </button>
            </div>
          </form>
        </div>
      )}
      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(0, 212, 255, 0.1); border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: rgba(0, 212, 255, 0.3); }
      `}</style>
    </>
  );
};

export default PolarisBrain;

import React, { useState, useEffect, useMemo } from 'react';
import { storageService } from '../services/storageService.ts';
import { Category, Document, VisitorActivity, AdminAccount } from '../types.ts';
import AdminStats from './AdminStats.tsx';

interface AdminDashboardProps {
  categories: Category[];
  documents: Document[];
  currentAdmin: AdminAccount | null;
  onRefresh?: () => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ categories, documents, currentAdmin, onRefresh }) => {
  const [activeTab, setActiveTab] = useState<'status' | 'stats' | 'architect' | 'spy' | 'ai_core' | 'keys' | 'logs'>('status');
  const [activities, setActivities] = useState<VisitorActivity[]>([]);
  const [accounts, setAccounts] = useState<AdminAccount[]>([]);
  const [isSyncing, setIsSyncing] = useState(false);
  const [bannedList, setBannedList] = useState<string[]>([]);
  const [aiStats, setAIStats] = useState<any[]>([]);
  const [iaMemory, setIaMemory] = useState('');

  // Wizard state
  const [publishStep, setPublishStep] = useState(0);
  const [isPublished, setIsPublished] = useState(false);
  const [newKeyName, setNewKeyName] = useState('');
  const [parentSelection, setParentSelection] = useState<string>('root');
  const [newItem, setNewItem] = useState({
    title: '',
    url: '',
    subCat: 'Matière'
  });

  const [generatedRow, setGeneratedRow] = useState<string>('');

  useEffect(() => {
    setActivities(storageService.getVisitorActivities());
    setAccounts(storageService.getAccounts());
    setBannedList(storageService.getBannedEmails());
    setAIStats(storageService.getAIStats());
    setIaMemory(storageService.getIAMemory());
  }, []);

  const fastestAI = useMemo(() => {
    if (aiStats.length === 0) return null;
    return [...aiStats].sort((a, b) => a.avgTime - b.avgTime)[0];
  }, [aiStats]);

  const handleSaveMemory = () => {
    storageService.saveIAMemory(iaMemory);
    storageService.addLog('CONFIG', `Mémoire du Nexus mise à jour.`);
    alert("🧠 Mémoire synchronisée avec le Cœur de l'IA.");
  };

  const handleManualSync = async () => {
    setIsSyncing(true);
    if (onRefresh) await onRefresh();
    setIsSyncing(false);
  };

  const handleAddKey = () => {
    if (!newKeyName) return;
    storageService.addAccount(newKeyName, 'MASTER');
    setAccounts(storageService.getAccounts());
    setNewKeyName('');
    storageService.addLog('ACCOUNT', `Nouvelle clé forgée : ${newKeyName}`);
  };

  const handleRemoveKey = (id: string) => {
    if (id === '0') return; 
    storageService.removeAccount(id);
    setAccounts(storageService.getAccounts());
    storageService.addLog('ACCOUNT', `Clé révoquée (ID: ${id})`);
  };

  const handleBan = (email: string) => {
    storageService.banEmail(email);
    setBannedList(storageService.getBannedEmails());
  };

  const handleUnban = (email: string) => {
    storageService.unbanEmail(email);
    setBannedList(storageService.getBannedEmails());
  };

  const handleFinalPublish = () => {
    const targetCat = categories.find(c => c.id === parentSelection);
    const catName = targetCat ? targetCat.name.toLowerCase() : 'terminale';
    setGeneratedRow(`"${newItem.title}","${newItem.url.trim()}","${catName}","${newItem.subCat.toLowerCase()}"`);
    setIsPublished(true);
    storageService.addLog('UPLOAD', `Archive formatée : ${newItem.title}`);
  };

  const resetWizard = () => {
    setPublishStep(0);
    setIsPublished(false);
    setGeneratedRow('');
    setNewItem({ title: '', url: '', subCat: 'Matière' });
  };

  return (
    <div className="bg-slate-950/40 rounded-[2rem] md:rounded-[3rem] border border-white/5 overflow-hidden backdrop-blur-3xl shadow-2xl flex flex-col min-h-[600px]">
      <div className="flex bg-black/60 overflow-x-auto no-scrollbar border-b border-white/10">
        {[
          { id: 'status', label: 'Matrice', icon: '☁️' },
          { id: 'stats', label: 'Analyse', icon: '📊' },
          { id: 'ai_core', label: 'Nexus AI', icon: '🧠' },
          { id: 'architect', label: 'Architecte', icon: '🏛️' },
          { id: 'spy', label: 'Espionnage', icon: '👁️' },
          ...(currentAdmin?.role === 'SUPER_MASTER' ? [{ id: 'keys', label: 'Clés', icon: '🔑' }] : []),
          { id: 'logs', label: 'Système', icon: '📟' }
        ].map(tab => (
          <button
            key={tab.id}
            onClick={() => { setActiveTab(tab.id as any); resetWizard(); }}
            className={`flex-1 py-6 px-8 text-[9px] font-black uppercase tracking-[0.2em] transition-all border-b-2 whitespace-nowrap flex items-center justify-center gap-3 ${
              activeTab === tab.id ? 'border-cyan-500 bg-cyan-500/5 text-white' : 'border-transparent text-white/30 hover:text-white'
            }`}
          >
            <span className="text-sm">{tab.icon}</span>
            {tab.label}
          </button>
        ))}
      </div>

      <div className="p-8 md:p-12 flex-1 flex flex-col overflow-y-auto max-h-[700px] no-scrollbar">
        {activeTab === 'status' && (
          <div className="space-y-8 animate-in">
            <div className="bg-gradient-to-br from-slate-900 to-black p-10 rounded-[2.5rem] border border-white/10 shadow-xl">
               <h3 className="text-xl font-black text-white uppercase italic mb-6">Contrôle Polaris</h3>
               <p className="text-white/40 text-[10px] uppercase font-bold tracking-[0.3em] mb-8 leading-loose">
                 Statut : <span className="text-emerald-400">Canal A (Compteur) Actif</span><br/>
                 Statut : <span className="text-amber-400">Accès Maître Autorisé</span>
               </p>
               <div className="flex gap-4">
                  <button onClick={handleManualSync} disabled={isSyncing} className="w-full bg-cyan-500/10 text-cyan-400 border border-cyan-500/20 py-5 rounded-2xl text-[10px] font-black uppercase tracking-widest">{isSyncing ? 'Sync Compteur...' : 'Rafraîchir Compteur'}</button>
               </div>
            </div>
          </div>
        )}

        {activeTab === 'stats' && <AdminStats />}

        {activeTab === 'ai_core' && (
          <div className="space-y-12 animate-in">
             <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="bg-slate-900/40 p-8 rounded-[2rem] border border-white/10">
                   <h4 className="text-[10px] font-black text-cyan-400 uppercase tracking-widest mb-6 italic">État de Santé du Nexus</h4>
                   <div className="space-y-4">
                      {aiStats.map((stat, idx) => {
                        const isFastest = fastestAI?.name === stat.name;
                        const isOffline = stat.status === 'offline';
                        return (
                          <div key={stat.name} className={`flex items-center justify-between p-4 bg-white/5 rounded-xl border transition-all ${isFastest ? 'border-cyan-400 shadow-[0_0_15px_rgba(0,212,255,0.2)]' : 'border-white/5'} ${isOffline ? 'opacity-50 border-red-500/50' : ''}`}>
                             <div className="flex items-center gap-3">
                                <div className={`w-2 h-2 rounded-full ${isOffline ? 'bg-red-500 animate-pulse' : 'bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.5)]'}`}></div>
                                <div>
                                   <p className="text-white font-black text-[12px] uppercase flex items-center gap-2">
                                      {stat.name}
                                      {isFastest && <span className="text-[7px] bg-cyan-500 text-black px-2 py-0.5 rounded-full font-black">ALPHA_SPEED</span>}
                                   </p>
                                   <p className="text-[8px] text-white/30 uppercase font-black">{isOffline ? 'FLUX INTERROMPU' : `${stat.count} RÉPONSES GÉNÉRÉES`}</p>
                                </div>
                             </div>
                             <div className="text-right">
                                <p className={`font-mono font-bold ${isFastest ? 'text-cyan-400 text-lg' : 'text-white/60'}`}>{isOffline ? '---' : `${stat.avgTime}ms`}</p>
                                <p className="text-[7px] text-white/20 uppercase font-black tracking-widest">LATENCE MOYENNE</p>
                             </div>
                          </div>
                        );
                      })}
                      {aiStats.length === 0 && <p className="text-[9px] text-white/20 text-center py-4 uppercase font-black tracking-widest">Initialisation des statistiques IA...</p>}
                   </div>
                </div>

                <div className="bg-slate-900/40 p-8 rounded-[2rem] border border-white/10 flex flex-col">
                   <h4 className="text-[10px] font-black text-white uppercase tracking-widest mb-6 italic">Injection de Mémoire</h4>
                   <p className="text-[8px] text-white/30 uppercase font-black mb-4">Modifiez le subconscient des assistants Polaris :</p>
                   <textarea 
                     value={iaMemory} 
                     onChange={(e) => setIaMemory(e.target.value)}
                     className="flex-1 bg-black/60 border border-white/10 rounded-2xl p-6 text-white text-[11px] outline-none focus:border-cyan-400 min-h-[150px] font-mono leading-relaxed"
                     placeholder="Votre créateur est Astarté Léon..."
                   ></textarea>
                   <button 
                     onClick={handleSaveMemory}
                     className="mt-6 bg-cyan-500 text-slate-950 py-4 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-neon hover:scale-105 active:scale-95 transition-all"
                   >
                     Mettre à jour la Mémoire
                   </button>
                </div>
             </div>
          </div>
        )}

        {activeTab === 'architect' && (
          <div className="max-w-4xl mx-auto w-full space-y-12 animate-in py-6">
            <div className="bg-white/[0.03] border border-white/10 rounded-[3.5rem] p-10 relative overflow-hidden backdrop-blur-3xl">
               {isPublished ? (
                 <div className="space-y-10 animate-in text-center">
                    <h3 className="text-white font-black uppercase tracking-[0.3em] text-2xl italic">FORMATAGE ARCHIVE</h3>
                    <p className="text-[10px] text-white/40 uppercase font-black">Copiez cette ligne pour votre index interne</p>
                    <div className="bg-black/90 rounded-[2rem] p-8 border border-cyan-500/30 font-mono text-cyan-400 break-all select-all text-[12px]">
                        {generatedRow}
                    </div>
                    <button onClick={resetWizard} className="w-full bg-white/5 text-white/60 py-5 rounded-2xl text-[10px] font-black uppercase border border-white/10">Nouveau</button>
                 </div>
               ) : (
                 <div className="space-y-10">
                   {publishStep === 0 && <button onClick={() => setPublishStep(1)} className="w-full bg-indigo-500/10 border border-indigo-500/30 p-14 rounded-[3rem] hover:bg-indigo-500 transition-all group font-black uppercase tracking-widest text-[12px] text-white">Préparer une Nouvelle Archive</button>}
                   {publishStep === 1 && <div className="space-y-8 animate-in"><input type="text" placeholder="Lien Drive..." value={newItem.url} onChange={e => setNewItem({...newItem, url: e.target.value})} className="w-full bg-black/60 border border-white/10 rounded-2xl p-6 text-white text-center outline-none focus:border-cyan-400" /><button onClick={() => setPublishStep(2)} className="w-full bg-white text-slate-950 py-5 rounded-2xl text-[10px] font-black uppercase">Suivant</button></div>}
                   {publishStep === 2 && <div className="space-y-8 animate-in"><input type="text" placeholder="Titre..." value={newItem.title} onChange={e => setNewItem({...newItem, title: e.target.value})} className="w-full bg-black/60 border border-white/10 rounded-2xl p-6 text-white text-center outline-none focus:border-cyan-400" /><button onClick={() => setPublishStep(3)} className="w-full bg-white text-slate-950 py-5 rounded-2xl text-[10px] font-black uppercase">Suivant</button></div>}
                   {publishStep === 3 && (
                     <div className="space-y-8 animate-in">
                       <select value={parentSelection} onChange={(e) => setParentSelection(e.target.value)} className="w-full bg-black/60 border border-white/10 rounded-2xl p-6 text-white text-center outline-none">
                         <option value="root">-- Secteur --</option>
                         {categories.filter(c => !c.parentId).map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                       </select>
                       <button onClick={() => setPublishStep(4)} className="w-full bg-white text-slate-950 py-5 rounded-2xl text-[10px] font-black uppercase">Suivant</button>
                     </div>
                   )}
                   {publishStep === 4 && <div className="space-y-8 animate-in"><input type="text" placeholder="Matière..." value={newItem.subCat} onChange={e => setNewItem({...newItem, subCat: e.target.value})} className="w-full bg-black/60 border border-white/10 rounded-2xl p-6 text-white text-center outline-none focus:border-cyan-400" /><button onClick={handleFinalPublish} className="w-full bg-cyan-500 text-slate-950 py-7 rounded-[2.5rem] text-[12px] font-black uppercase tracking-[0.5em]">GÉNÉRER</button></div>}
                 </div>
               )}
            </div>
          </div>
        )}

        {activeTab === 'spy' && (
          <div className="space-y-12 animate-in">
             <div className="bg-black/40 rounded-[2rem] border border-white/5 p-6 overflow-x-auto shadow-2xl">
                <table className="w-full text-left">
                    <thead><tr className="text-[8px] uppercase font-black text-white/20 tracking-[0.4em] border-b border-white/10"><th className="pb-4">Visiteur</th><th className="pb-4">Action</th><th className="pb-4 text-right">Contrôle</th></tr></thead>
                    <tbody className="divide-y divide-white/[0.04]">
                        {activities.map(act => (
                            <tr key={act.id}>
                                <td className="py-4 text-[10px] text-white/80 font-bold">{act.email || 'Anonyme'}</td>
                                <td className="py-4 text-[9px] text-cyan-400 italic">{act.fileName || 'Archive'}</td>
                                <td className="py-4 text-right">
                                  {currentAdmin?.role === 'SUPER_MASTER' && act.email && (
                                    bannedList.includes(act.email) ? 
                                    <button onClick={() => handleUnban(act.email!)} className="text-[8px] font-black uppercase text-emerald-400 hover:underline">Réactiver</button> :
                                    <button onClick={() => handleBan(act.email!)} className="text-[8px] font-black uppercase text-red-500 hover:underline">Bannir</button>
                                  )}
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
             </div>
          </div>
        )}

        {activeTab === 'keys' && currentAdmin?.role === 'SUPER_MASTER' && (
          <div className="space-y-10 animate-in">
            <div className="bg-slate-900/40 border border-white/10 rounded-[2.5rem] p-8">
               <h3 className="text-[12px] font-black text-white uppercase italic mb-6 text-cyan-400 tracking-widest">Forger une Clé</h3>
               <div className="flex gap-4">
                  <input type="text" placeholder="Pseudo..." value={newKeyName} onChange={e => setNewKeyName(e.target.value)} className="flex-1 bg-black/60 border border-white/10 rounded-2xl p-5 text-white text-[12px] outline-none" />
                  <button onClick={handleAddKey} className="bg-white text-slate-950 px-10 rounded-2xl text-[10px] font-black uppercase">Forger</button>
               </div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
               {accounts.map(acc => (
                 <div key={acc.id} className="bg-white/[0.03] p-6 rounded-3xl border border-white/5 flex items-center justify-between">
                    <div><p className="text-[13px] font-black text-white">{acc.username}</p><p className="text-[8px] text-white/30 uppercase font-black">{acc.role}</p></div>
                    {acc.id !== '0' && <button onClick={() => handleRemoveKey(acc.id)} className="text-red-500 text-xs font-black uppercase tracking-widest">Révoquer</button>}
                 </div>
               ))}
            </div>
          </div>
        )}

        {activeTab === 'logs' && (
          <div className="space-y-3 animate-in">
            {storageService.getLogs().map(log => (
              <div key={log.id} className="bg-white/[0.02] p-4 rounded-xl text-[10px] font-mono border border-white/5 flex gap-4">
                   <span className="text-white/10">[{log.timestamp}]</span>
                   <span className="text-cyan-400 font-black uppercase">{log.action}</span>
                   <span className="text-white/60">"{log.details}"</span>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminDashboard;

import React, { useState, useEffect } from 'react';
import { Document } from '../types';
