        aiService.fetchStepFun(messages, prompt)
      ]);

      // Analyse automatique des requêtes
      storageService.logQueryForAnalysis(storageService.getUserEmail(), lastUserQuery, result.text);

      return result;
    } catch (aggregateError) {
      storageService.addLog('SYSTEM', "Échec critique du Nexus IA.");
      throw new Error("BLACKOUT_IA");
    }
  }
};

