             </div>
             <div className="flex flex-col items-start text-left">
                <span className="text-[8px] font-black uppercase text-cyan-400/60 tracking-widest leading-none">Nexus Protocol</span>
                <span className="text-[14px] font-black text-white">Polaris Brain</span>
             </div>
          </div>
        </button>
      </div>

      {isOpen && (
        <div className="fixed bottom-0 right-0 w-full sm:bottom-6 sm:right-6 sm:w-[400px] h-[100dvh] sm:h-[600px] max-h-[100dvh] sm:max-h-[85vh] z-[8000] bg-slate-950/95 backdrop-blur-3xl border-t sm:border border-white/10 sm:rounded-[2.5rem] shadow-2xl flex flex-col overflow-hidden animate-in slide-in-from-bottom-10 duration-500">

          <div className="bg-slate-900/50 p-6 border-b border-white/5 flex items-center justify-between">
            <div className="flex items-center gap-4">
              <div className="w-10 h-10 bg-cyan-500/10 border border-cyan-500/30 rounded-xl flex items-center justify-center">
