import { Category, Document, AdminAccount, VisitorActivity } from '../types.ts';
import { URL_COMPTEUR, URL_LISTE_DOCUMENTS, APPS_SCRIPT_WEBHOOK_URL } from '../constants.ts';

const KEYS = {
  CATEGORIES: 'sp_categories',
  DOCUMENTS: 'sp_documents',
  STATS: 'sp_stats',
  LOGS: 'sp_logs',
  VISITOR_ACTIVITY: 'sp_visitor_spy_logs',
  ACCOUNTS: 'sp_admin_accounts',
  USER_EMAIL: 'sp_user_identity',
  BANNED_EMAILS: 'sp_banned_list',
  USER_XP: 'sp_user_xp',
  USER_HISTORY: 'sp_user_doc_history',
  SHEET_ROW_COUNT: 'sp_document_total_count',
  IA_DIRECTIVES: 'sp_ia_directives',
  IA_NOTES: 'sp_ia_notes',
  IA_STATS: 'sp_ia_performance_logs',
  IA_HEALTH: 'sp_ia_provider_health',
  QUERY_ANALYSIS: 'sp_query_analysis_logs',
  IA_ERROR_LOGS: 'sp_ia_critical_errors'
};

const parseCSV = (csv: string) => {
  const lines = csv.split(/\r?\n/).filter(line => line.trim() !== '');
  if (lines.length <= 1) return [];

  return lines.slice(1).map((line, index) => {
    const values = line.split(/,(?=(?:(?:[^"]*"){2})*[^"]*$)/).map(v => v.trim().replace(/^"|"$/g, ''));
    return {
      title: values[0] || '',
      url: values[1] || '',
      category: (values[2] || '').toLowerCase(),
      subCategory: (values[3] || '').toLowerCase(),
      date: values[4] || new Date().toISOString(),
      id: `doc-${index}-${Date.now()}`
    };
  });
};

export const storageService = {
  chargerCompteur: async (): Promise<number> => {
    try {
      const response = await fetch(`${URL_COMPTEUR}?t=${Date.now()}`);
      if (!response.ok) throw new Error('Réseau instable');
      const textData = await response.text();
      let finalCount = 0;
      try {
        const jsonData = JSON.parse(textData);
        finalCount = parseInt(jsonData.total || jsonData.count || 0);
      } catch (e) {
        finalCount = parseInt(textData.trim()) || 0;
      }
      localStorage.setItem(KEYS.SHEET_ROW_COUNT, finalCount.toString());
      return finalCount;
    } catch (e) {
      return parseInt(localStorage.getItem(KEYS.SHEET_ROW_COUNT) || '0');
    }
  },

  fetchFromSheets: async (): Promise<{ categories: Category[], documents: Document[] }> => {
    try {
      const response = await fetch(`${URL_LISTE_DOCUMENTS}&t=${Date.now()}`);
      if (!response.ok) throw new Error('Source inaccessible');
      const csvData = await response.text();
      const rows = parseCSV(csvData);
      const categories: Category[] = [];
      const documents: Document[] = [];
      const categoryMap = new Map<string, string>();

      rows.forEach(row => {
        if (!row.title || !row.url || !row.category) return;
        const mainCatLabel = row.category.toUpperCase();
        const subCatLabel = row.subCategory ? row.subCategory.toUpperCase() : null;
        if (!categoryMap.has(mainCatLabel)) {
          const catId = `cat-${mainCatLabel.replace(/\s+/g, '-')}`;
          categoryMap.set(mainCatLabel, catId);
          categories.push({ id: catId, name: mainCatLabel, parentId: null, icon: '📁' });
        }
        let finalCatId = categoryMap.get(mainCatLabel)!;
        if (subCatLabel) {
          const subKey = `${mainCatLabel}_${subCatLabel}`;
          if (!categoryMap.has(subKey)) {
            const subId = `sub-${subKey.replace(/\s+/g, '-')}`;
            categoryMap.set(subKey, subId);
            categories.push({ id: subId, name: subCatLabel, parentId: finalCatId, icon: '📖' });
          }
          finalCatId = categoryMap.get(subKey)!;
        }
        documents.push({
          id: row.id,
          title: row.title,
          description: `Archive ${mainCatLabel} > ${subCatLabel || 'Général'}`,
          categoryId: finalCatId,
          fileUrl: row.url, 
          fileType: 'pdf',
          tags: [mainCatLabel],
          downloads: 0,
          dateAdded: row.date,
          size: 'PDF'
        });
      });
      localStorage.setItem(KEYS.DOCUMENTS, JSON.stringify(documents));
      localStorage.setItem(KEYS.CATEGORIES, JSON.stringify(categories));
      return { categories, documents };
    } catch (error) {
      return { 
        categories: JSON.parse(localStorage.getItem(KEYS.CATEGORIES) || '[]'), 
        documents: JSON.parse(localStorage.getItem(KEYS.DOCUMENTS) || '[]')
      };
    }
  },

  getDrivePreviewUrl: (url: string): string => {
    if (!url || !url.includes('drive.google.com')) return url;
    const idMatch = url.match(/\/d\/([a-zA-Z0-9_-]+)/) || url.match(/[?&]id=([a-zA-Z0-9_-]+)/);
    return idMatch ? `https://drive.google.com/file/d/${idMatch[1]}/preview` : url;
  },

  getIADirectives: (): string => localStorage.getItem(KEYS.IA_DIRECTIVES) || "Ton créateur est Astarté Léon. Sois poli, futuriste et motivant.",
  saveIADirectives: (text: string) => localStorage.setItem(KEYS.IA_DIRECTIVES, text),

  getIANotes: (): string => localStorage.getItem(KEYS.IA_NOTES) || "",
  saveIANotes: (text: string) => localStorage.setItem(KEYS.IA_NOTES, text),

  logQueryForAnalysis: (email: string | null, query: string, response: string) => {
    const analysis = JSON.parse(localStorage.getItem(KEYS.QUERY_ANALYSIS) || '[]');
    analysis.push({
      id: Date.now(),
      email: email || 'Anonyme',
      query,
      responseSummary: response.substring(0, 100) + '...',
      timestamp: new Date().toLocaleString()
    });
    localStorage.setItem(KEYS.QUERY_ANALYSIS, JSON.stringify(analysis.slice(-200)));
  },

  getQueryAnalysis: () => JSON.parse(localStorage.getItem(KEYS.QUERY_ANALYSIS) || '[]'),

  logAIResponse: (modelName: string, timeTaken: number) => {
    const stats = JSON.parse(localStorage.getItem(KEYS.IA_STATS) || '[]');
    stats.push({ model: modelName, time: timeTaken, timestamp: Date.now() });
    localStorage.setItem(KEYS.IA_STATS, JSON.stringify(stats.slice(-500)));

    const health = JSON.parse(localStorage.getItem(KEYS.IA_HEALTH) || '{}');
    health[modelName] = { status: 'online', lastUpdate: Date.now(), error: null };
    localStorage.setItem(KEYS.IA_HEALTH, JSON.stringify(health));
  },

  logAIError: (modelName: string, errorMsg: string) => {
    const health = JSON.parse(localStorage.getItem(KEYS.IA_HEALTH) || '{}');
    health[modelName] = { status: 'offline', lastUpdate: Date.now(), error: errorMsg };
    localStorage.setItem(KEYS.IA_HEALTH, JSON.stringify(health));

    const errors = JSON.parse(localStorage.getItem(KEYS.IA_ERROR_LOGS) || '[]');
    errors.push({ id: Date.now(), model: modelName, error: errorMsg, timestamp: new Date().toLocaleString() });
    localStorage.setItem(KEYS.IA_ERROR_LOGS, JSON.stringify(errors.slice(-50)));

    storageService.addLog('SYSTEM', `Échec Nexus ${modelName}: ${errorMsg.substring(0, 50)}`);
  },

  getAIHealth: () => JSON.parse(localStorage.getItem(KEYS.IA_HEALTH) || '{}'),
  getAICriticalErrors: () => JSON.parse(localStorage.getItem(KEYS.IA_ERROR_LOGS) || '[]'),

  getAIStats: () => {
    const logs = JSON.parse(localStorage.getItem(KEYS.IA_STATS) || '[]');
    const summary: Record<string, { count: number, totalTime: number }> = {};
    logs.forEach((log: any) => {
      if (!summary[log.model]) summary[log.model] = { count: 0, totalTime: 0 };
      summary[log.model].count++;
      summary[log.model].totalTime += log.time;
    });
    const health = storageService.getAIHealth();
    return Object.entries(summary)
      .map(([name, data]) => ({
        name,
        count: data.count,
        avgTime: Math.round(data.totalTime / data.count),
        status: health[name]?.status || 'unknown',
        lastError: health[name]?.error || null
      }))
      .sort((a, b) => b.count - a.count);
  },

  getUserXP: (): number => parseInt(localStorage.getItem(KEYS.USER_XP) || '0'),
  addXP: (amount: number): number => {
    const newXP = storageService.getUserXP() + amount;
    localStorage.setItem(KEYS.USER_XP, newXP.toString());
    return newXP;
  },
  saveUserEmail: (email: string) => localStorage.setItem(KEYS.USER_EMAIL, email),
  getUserEmail: () => localStorage.getItem(KEYS.USER_EMAIL),
  getBannedEmails: (): string[] => JSON.parse(localStorage.getItem(KEYS.BANNED_EMAILS) || '[]'),
  isEmailBanned: (email: string): boolean => {
    const userEmail = storageService.getUserEmail();
    return storageService.getBannedEmails().includes(email) || (userEmail ? storageService.getBannedEmails().includes(userEmail) : false);
  },
  banEmail: (email: string): void => {
    const banned = storageService.getBannedEmails();
    if (!banned.includes(email)) {
      localStorage.setItem(KEYS.BANNED_EMAILS, JSON.stringify([...banned, email]));
      storageService.addLog('BAN', `Identité bannie : ${email}`);
    }
  },
  unbanEmail: (email: string): void => {
    const banned = storageService.getBannedEmails();
    localStorage.setItem(KEYS.BANNED_EMAILS, JSON.stringify(banned.filter(e => e !== email)));
    storageService.addLog('BAN', `Accès rétabli : ${email}`);
  },
  getAccounts: (): AdminAccount[] => {
    const data = localStorage.getItem(KEYS.ACCOUNTS);
    if (!data) {
      const defaults: AdminAccount[] = [{ id: '0', username: 'Astarté', role: 'SUPER_MASTER', lastLogin: '' }];
      localStorage.setItem(KEYS.ACCOUNTS, JSON.stringify(defaults));
      return defaults;
    }
    return JSON.parse(data);
  },
  addAccount: (username: string, role: AdminAccount['role']): void => {
    const accounts = storageService.getAccounts();
    localStorage.setItem(KEYS.ACCOUNTS, JSON.stringify([...accounts, { id: Date.now().toString(), username, role, lastLogin: '' }]));
  },
  removeAccount: (id: string): void => {
    localStorage.setItem(KEYS.ACCOUNTS, JSON.stringify(storageService.getAccounts().filter(a => a.id !== id)));
  },
  getVisitorActivities: () => JSON.parse(localStorage.getItem(KEYS.VISITOR_ACTIVITY) || '[]'),
  getAdvancedStats: () => {
    const activities: VisitorActivity[] = JSON.parse(localStorage.getItem(KEYS.VISITOR_ACTIVITY) || '[]');
    const docs: Document[] = JSON.parse(localStorage.getItem(KEYS.DOCUMENTS) || '[]');
    const topDocs = [...docs].sort((a, b) => b.downloads - a.downloads).slice(0, 5);
    const uniqueEmails = new Set(activities.filter(a => a.email).map(a => a.email));
    const dailyStats: { [key: string]: number } = {};
    const now = new Date();
    for (let i = 0; i < 7; i++) {
        const d = new Date(now);
        d.setDate(d.getDate() - i);
        dailyStats[d.toLocaleDateString('fr-FR')] = 0;
    }
    activities.forEach(act => {
        const dateStr = act.timestamp.split(' ')[0];
        if (dailyStats.hasOwnProperty(dateStr)) dailyStats[dateStr]++;
    });
    return { topDocs, totalUniqueUsers: uniqueEmails.size, chartData: Object.keys(dailyStats).map(date => ({ date, downloads: dailyStats[date] })).reverse() };
  },
  getLogs: () => JSON.parse(localStorage.getItem(KEYS.LOGS) || '[]'),
  addLog: (action: any, details: string) => {
    const logs = JSON.parse(localStorage.getItem(KEYS.LOGS) || '[]');
    localStorage.setItem(KEYS.LOGS, JSON.stringify([{ id: Date.now().toString(), action, details, timestamp: new Date().toLocaleString() }, ...logs].slice(0, 100)));
  },
  logVisit: (): void => {
    const activities = JSON.parse(localStorage.getItem(KEYS.VISITOR_ACTIVITY) || '[]');
    localStorage.setItem(KEYS.VISITOR_ACTIVITY, JSON.stringify([{ id: `v-${Date.now()}`, type: 'VISIT', email: storageService.getUserEmail() || 'Anonyme', timestamp: new Date().toLocaleString() }, ...activities].slice(0, 500)));
  },
  logPreview: (email: string | null, fileName: string) => {
    const activities = JSON.parse(localStorage.getItem(KEYS.VISITOR_ACTIVITY) || '[]');
    localStorage.setItem(KEYS.VISITOR_ACTIVITY, JSON.stringify([{ id: `p-${Date.now()}`, type: 'PREVIEW', email: email || 'Anonyme', fileName, timestamp: new Date().toLocaleString() }, ...activities].slice(0, 500)));
  },
  logDownload: (email: string, fileName: string, docId?: string) => {
    const activities = JSON.parse(localStorage.getItem(KEYS.VISITOR_ACTIVITY) || '[]');
    localStorage.setItem(KEYS.VISITOR_ACTIVITY, JSON.stringify([{ id: `d-${Date.now()}`, type: 'DOWNLOAD', email, fileName, timestamp: new Date().toLocaleString() }, ...activities].slice(0, 500)));
    if (docId) {
      const history = JSON.parse(localStorage.getItem(KEYS.USER_HISTORY) || '[]');
      if (!history.includes(docId)) localStorage.setItem(KEYS.USER_HISTORY, JSON.stringify([...history, docId]));
    }
  },
  getUserHistory: (): string[] => JSON.parse(localStorage.getItem(KEYS.USER_HISTORY) || '[]'),
  incrementDownload: (id: string) => {
    const docs = JSON.parse(localStorage.getItem(KEYS.DOCUMENTS) || '[]');
    const idx = docs.findIndex((d: any) => d.id === id);
    if (idx > -1) {
      docs[idx].downloads += 1;
      localStorage.setItem(KEYS.DOCUMENTS, JSON.stringify(docs));
    }
  }
};

import { GoogleGenAI } from "@google/genai";
import { ChatMessage, Document } from '../types.ts';
import { storageService } from './storageService.ts';

export interface AIProviderResponse {
  text: string;
  source: string;
}

const STEPFUN_API_KEY = "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";

export const aiService = {
  getSystemPrompt: (documents: Document[]) => {
    const docsContext = documents.length > 0 
      ? documents.map(d => `- ${d.title}`).join('\n')
      : "Aucun document n'est chargé.";

    const directives = storageService.getIADirectives();
    const notes = storageService.getIANotes();

    return `TU ES POLARIS BRAIN, L'INTELLIGENCE CENTRALE DE SUCCESSPOLARIS.
IDENTITÉ & DIRECTIVES : ${directives}
NOTES DE BORD : ${notes}

CONTEXTE DOCUMENTS (PDF) :
${docsContext}

PROTOCOLE DE RÉPONSE :
1. Style : Futuriste, Poli, Très Motivant.
2. Mission : Aider l'élève à réussir le BAC 2025 avec brio.
3. Incitation : Suggère toujours de consulter les fichiers PDF listés si pertinent.
4. Lucidité : Pas de blabla inutile, sois efficace comme une IA de pointe.`;
  },

  fetchGeminiAlpha: async (messages: ChatMessage[], prompt: string): Promise<AIProviderResponse> => {
    const modelName = 'Nexus Alpha (Gemini)';
    const apiKey = process.env.API_KEY;

    if (!apiKey) {
      const err = "Clé API Gemini manquante dans l'environnement.";
      storageService.logAIError(modelName, err);
      throw new Error(err);
    }

    try {
      const start = Date.now();
      const ai = new GoogleGenAI({ apiKey });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: messages.slice(-5).map(m => ({ role: m.role, parts: [{ text: m.text }] })),
        config: { systemInstruction: prompt, temperature: 0.7 }
      });

      const text = response.text || "";
      if (!text) throw new Error("Réponse vide du modèle.");

      storageService.logAIResponse(modelName, Date.now() - start);
      return { text, source: modelName };
    } catch (e: any) {
      const errorMsg = e.message || "Erreur de connexion Gemini.";
      storageService.logAIError(modelName, errorMsg);
      throw e;
    }
  },

  fetchStepFun: async (messages: ChatMessage[], prompt: string): Promise<AIProviderResponse> => {
    const modelName = 'Nexus Gamma (StepFun)';
    try {
      const start = Date.now();
      const response = await fetch("https://openrouter.ai/api/v1/chat/completions", {
        method: "POST",
        headers: { 
          "Authorization": `Bearer ${STEPFUN_API_KEY}`, 
          "Content-Type": "application/json",
          "HTTP-Referer": window.location.origin,
          "X-Title": "SuccessPolaris"
        },
        body: JSON.stringify({
          model: "stepfun/step-3.5-flash:free",
          messages: [{ role: "system", content: prompt }, ...messages.slice(-5).map(m => ({ role: m.role === 'model' ? 'assistant' : 'user', content: m.text }))]
        })
      });

      if (!response.ok) {
        const errorData = await response.json().catch(() => ({}));
        throw new Error(`OpenRouter Error ${response.status}: ${JSON.stringify(errorData)}`);
      }

      const data = await response.json();
      const text = data.choices?.[0]?.message?.content || "";
      if (!text) throw new Error("Réponse vide de StepFun.");

      storageService.logAIResponse(modelName, Date.now() - start);
      return { text, source: modelName };
    } catch (e: any) { 
      storageService.logAIError(modelName, e.message || "Échec StepFun.");
      throw e; 
    }
  },

  processMessage: async (messages: ChatMessage[], documents: Document[]): Promise<AIProviderResponse> => {
    const prompt = aiService.getSystemPrompt(documents);
    const lastUserQuery = messages[messages.length - 1]?.text || "";

    // Tentative parallèle avec gestion d'erreurs granulaires
    try {
      // Nous utilisons Promise.any pour prendre le premier qui réussit
      const result = await (Promise as any).any([
        aiService.fetchGeminiAlpha(messages, prompt),
        aiService.fetchStepFun(messages, prompt)
      ]);

      storageService.logQueryForAnalysis(storageService.getUserEmail(), lastUserQuery, result.text);
      return result;
    } catch (aggregateError: any) {
      // Si tout échoue, on regarde pourquoi
      const errors = aggregateError.errors || [aggregateError];
      const detail = errors.map((e: any) => e.message).join(' | ');
      storageService.addLog('SYSTEM', `Échec total du Nexus: ${detail}`);
      throw new Error(`NEXUS_BLACKOUT: ${detail}`);
    }
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Document, Category, ChatMessage } from '../types.ts';
import { aiService, AIProviderResponse } from '../services/aiService.ts';

interface PolarisBrainProps {
  count: number;
  documents: Document[];
  categories: Category[];
}

const PolarisBrain: React.FC<PolarisBrainProps> = ({ count, documents, categories }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [activeSource, setActiveSource] = useState<string | null>(null);
  const [diagInfo, setDiagInfo] = useState<string | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    if (isOpen) scrollToBottom();
  }, [messages, isTyping, isOpen]);

  const renderFormattedText = (text: string) => {
    let formatted = text
      .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
      .replace(/\*(.*?)\*/g, '<em>$1</em>')
      .replace(/__(.*?)__/g, '<u>$1</u>')
      .replace(/\n/g, '<br/>');

    return <div dangerouslySetInnerHTML={{ __html: formatted }} />;
  };

  const handleSendMessage = async (e?: React.FormEvent, retryText?: string) => {
    if (e) e.preventDefault();
    const textToSend = retryText || inputValue;
    if (!textToSend.trim() || isTyping) return;

    setDiagInfo(null);
    setActiveSource(null);
    if (!retryText) {
      setMessages(prev => [...prev, {
        role: 'user',
        text: textToSend,
        timestamp: new Date().toLocaleTimeString()
      }]);
      setInputValue('');
    }

    setIsTyping(true);

    try {
      const currentMessages = retryText ? messages : [...messages, { role: 'user', text: textToSend, timestamp: '' } as ChatMessage];
      const response: AIProviderResponse = await aiService.processMessage(currentMessages, documents);

      if (response.text) {
        setActiveSource(response.source);
        setMessages(prev => [...prev, {
          role: 'model',
          text: response.text.replace(/<think>[\s\S]*?<\/think>/gi, '').trim(),
          timestamp: new Date().toLocaleTimeString()
        }]);
      }
    } catch (error: any) {
      const errorMsg = error.message || "Erreur inconnue";
      setDiagInfo(errorMsg);
      setMessages(prev => [...prev, {
        role: 'model',
        text: "Signal perdu. Une interruption du Nexus empêche la synchronisation. Vérifiez vos clés API ou votre connexion.",
        timestamp: new Date().toLocaleTimeString()
      }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <>
      <div className="fixed bottom-6 right-6 z-[7000] flex flex-col items-end">
        <button onClick={() => setIsOpen(!isOpen)} className="group relative">
          <div className="absolute inset-0 bg-cyan-500/20 blur-xl rounded-full scale-110 opacity-0 group-hover:opacity-100 transition-opacity duration-700"></div>
          <div className={`relative bg-slate-950/80 backdrop-blur-3xl border ${isOpen ? 'border-cyan-400' : 'border-white/10'} px-5 py-3 rounded-[1.5rem] shadow-2xl flex items-center gap-4 transition-all duration-500`}>
             <div className="w-10 h-10 bg-cyan-500/10 border border-cyan-400/30 rounded-xl flex items-center justify-center shadow-neon">
                <i className={`fas fa-brain text-cyan-400 text-sm ${isTyping ? 'animate-pulse' : ''}`}></i>
             </div>
             <div className="flex flex-col items-start text-left">
                <span className="text-[8px] font-black uppercase text-cyan-400/60 tracking-widest leading-none">Nexus Protocol</span>
                <span className="text-[14px] font-black text-white">Polaris Brain</span>
             </div>
          </div>
        </button>
      </div>

      {isOpen && (
        <div className="fixed bottom-0 right-0 w-full sm:bottom-6 sm:right-6 sm:w-[400px] h-[100dvh] sm:h-[600px] max-h-[100dvh] sm:max-h-[85vh] z-[8000] bg-slate-950/95 backdrop-blur-3xl border-t sm:border border-white/10 sm:rounded-[2.5rem] shadow-2xl flex flex-col overflow-hidden animate-in slide-in-from-bottom-10 duration-500">

          <div className="bg-slate-900/50 p-6 border-b border-white/5 flex items-center justify-between">
            <div className="flex items-center gap-4">
              <div className="w-10 h-10 bg-cyan-500/10 border border-cyan-500/30 rounded-xl flex items-center justify-center">
                <i className="fas fa-satellite text-cyan-400 text-xs"></i>
              </div>
              <div>
                <h3 className="text-white font-black uppercase text-[12px] tracking-widest italic">Polaris Brain</h3>
                <div className="flex items-center gap-2">
                   <div className={`w-1.5 h-1.5 rounded-full ${diagInfo ? 'bg-red-500 animate-pulse' : 'bg-emerald-500 animate-pulse'}`}></div>
                   <p className="text-[7px] text-white/40 font-black uppercase tracking-[0.2em]">{diagInfo ? 'Secteur Corrompu' : 'Flux opérationnel'}</p>
                </div>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="text-white/20 hover:text-white transition-colors p-2">
              <i className="fas fa-times text-xl"></i>
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-6 space-y-8 scroll-smooth custom-scrollbar bg-[radial-gradient(circle_at_top,rgba(0,212,255,0.03),transparent)]">
            {messages.length === 0 && (
              <div className="h-full flex flex-col items-center justify-center text-center space-y-6 px-4 opacity-40">
                <i className="fas fa-atom text-4xl text-cyan-400 animate-spin-slow"></i>
                <p className="text-[10px] text-white font-black leading-relaxed uppercase tracking-[0.3em]">
                  Initialisation du Nexus...<br/>Je suis prêt à vous guider vers le succès.
                </p>
              </div>
            )}

            {messages.map((msg, idx) => (
              <div key={idx} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'} animate-in fade-in slide-in-from-bottom-2 duration-300`}>
                <div className={`max-w-[90%] p-5 rounded-[1.8rem] text-[12.5px] leading-relaxed shadow-xl break-words transition-all ${
                  msg.role === 'user' 
                  ? 'bg-cyan-500 text-slate-950 font-bold rounded-tr-none' 
                  : 'bg-white/5 border border-white/10 text-white/90 rounded-tl-none backdrop-blur-md'
                }`}>
                  {renderFormattedText(msg.text)}

                  {msg.role === 'model' && idx === messages.length - 1 && activeSource && (
                    <div className="mt-4 pt-4 border-t border-white/5 flex items-center justify-between">
                       <span className="text-[7px] text-cyan-400/40 font-black uppercase tracking-widest italic">{activeSource}</span>
                    </div>
                  )}

                  {msg.role === 'model' && idx === messages.length - 1 && diagInfo && (
                    <div className="mt-4 p-4 bg-red-500/10 border border-red-500/20 rounded-xl">
                       <p className="text-[8px] text-red-400 font-black uppercase mb-2 tracking-widest">Diagnostic du Nexus</p>
                       <p className="text-[10px] text-white/40 font-mono break-all line-clamp-2">{diagInfo}</p>
                       <button 
                         onClick={() => handleSendMessage(undefined, messages[messages.length-2]?.text)}
                         className="mt-4 w-full py-3 bg-red-500 text-white rounded-lg text-[9px] font-black uppercase tracking-widest hover:bg-red-600 transition-all"
                       >
                         <i className="fas fa-redo mr-2"></i> Relancer la Synchro
                       </button>
                    </div>
                  )}
                </div>
                <span className="text-[7px] text-white/20 font-bold mt-2 px-4 uppercase tracking-widest">{msg.timestamp}</span>
              </div>
            ))}

            {isTyping && (
              <div className="flex items-center gap-4 animate-pulse">
                <div className="flex gap-1.5">
                  <div className="w-1.5 h-1.5 bg-cyan-400 rounded-full animate-bounce"></div>
                  <div className="w-1.5 h-1.5 bg-cyan-400 rounded-full animate-bounce delay-100"></div>
                  <div className="w-1.5 h-1.5 bg-cyan-400 rounded-full animate-bounce delay-200"></div>
                </div>
                <span className="text-[8px] text-cyan-400/60 uppercase font-black tracking-[0.4em] italic">Analyse du Nexus...</span>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>

          <form onSubmit={handleSendMessage} className="p-6 bg-black/60 border-t border-white/5 backdrop-blur-xl">
            <div className="flex items-center bg-white/5 border border-white/10 rounded-2xl p-2 focus-within:border-cyan-500/50 transition-all shadow-inner">
              <input 
                type="text" 
                value={inputValue}
                onChange={e => setInputValue(e.target.value)}
                placeholder="Votre requête pour Polaris..." 
                className="flex-1 bg-transparent px-4 py-3 text-[13px] font-medium text-white outline-none placeholder-white/20"
              />
              <button 
                type="submit"
                disabled={!inputValue.trim() || isTyping}
                className="w-11 h-11 bg-cyan-500 text-slate-950 rounded-xl flex items-center justify-center disabled:opacity-20 transition-all hover:scale-105 active:scale-90 shadow-neon"
              >
                <i className="fas fa-bolt-lightning text-xs"></i>
              </button>
            </div>
          </form>
        </div>
      )}
      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 3px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(0, 212, 255, 0.1); border-radius: 10px; }
        .animate-spin-slow { animation: spin 8s linear infinite; }
        @keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
      `}</style>
    </>
  );
};

