      // Analyse et Archivage de la requête
      storageService.logQueryForAnalysis(storageService.getUserEmail(), lastQuery, result.text);

      return result;
    } catch (e) {
      throw new Error("NEXUS_TOTAL_BLACKOUT");
    }
  }
};

