import { GoogleGenAI } from "@google/genai";
import { ChatMessage, Document } from '../types.ts';
import { storageService } from './storageService.ts';

export interface AIProviderResponse {
  text: string;
  source: string;
  isFallback: boolean;
  status: 'SUCCESS' | 'RELAY' | 'CRITICAL';
}

export const aiService = {
  getSystemInstruction: (documents: Document[]) => {
    const docsContext = documents.length > 0 
      ? documents.map(d => `- ${d.title} (ID: ${d.id})`).join('\n')
      : "Aucune archive PDF détectée.";

    const directives = storageService.getIADirectives();
    const notes = storageService.getIANotes();

    return `TU ES POLARIS BRAIN, L'ENTITÉ D'ASSISTANCE DE SUCCESSPOLARIS.
STYLE : Futuriste, Poli, Très Motivant. Spécialiste BAC 2025.
DIRECTIVES ADMIN : ${directives}
NOTES DE COURS : ${notes}

ARCHIVES PDF DISPONIBLES :
${docsContext}

PROTOCOLE :
1. Aide l'élève pour le BAC 2025 avec précision.
2. Suggère TOUJOURS les fichiers PDF mentionnés ci-dessus si pertinent.
3. Si tu utilises ta réflexion, sois structuré.`;
  },

  /**
   * IA 1 : OpenRouter (Modèle Réflexion)
   * Ce canal est le canal PRIORITAIRE.
   */
  fetchPrimaryAI: async (messages: ChatMessage[], systemInstruction: string): Promise<string> => {
    const apiKey = (process.env as any).NEXT_PUBLIC_API_KEY_1;
    if (!apiKey) throw new Error("CLÉ_API_1_ABSENTE");

    const response = await fetch("https://openrouter.ai/api/v1/chat/completions", {
      method: "POST",
      headers: {
        "Authorization": `Bearer ${apiKey}`,
        "HTTP-Referer": "https://successpolaris.com",
        "X-Title": "SuccessPolaris Astral Nexus",
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        // On utilise un modèle qui "réfléchit" (DeepSeek R1 est excellent pour ça sur OpenRouter)
        model: "deepseek/deepseek-r1:free", 
        messages: [
          { role: "system", content: systemInstruction },
          ...messages.map(m => ({
            role: m.role === 'model' ? 'assistant' : 'user',
            content: m.text
          }))
        ],
        temperature: 0.6
      })
    });

    if (!response.ok) {
      const errorData = await response.json();
      throw new Error(errorData.error?.message || `Erreur Signal ${response.status}`);
    }

    const data = await response.json();
    return data.choices?.[0]?.message?.content || "";
  },

  /**
   * CANAL DE SECOURS : Gemini SDK
   * Utilisé uniquement si l'IA 1 échoue.
   */
  fetchGeminiFallback: async (messages: ChatMessage[], systemInstruction: string): Promise<string> => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: messages.map(m => ({
        role: m.role,
        parts: [{ text: m.text }]
      })),
      config: {
        systemInstruction: systemInstruction,
        thinkingConfig: { thinkingBudget: 16000 },
        temperature: 0.7
      },
    });
    return response.text || "";
  },

  processMessage: async (messages: ChatMessage[], documents: Document[]): Promise<AIProviderResponse> => {
    const systemInstruction = aiService.getSystemInstruction(documents);
    const start = Date.now();

    // TENTATIVE 1 : IA PRIMAIRE (TON IA 1)
    try {
      const text = await aiService.fetchPrimaryAI(messages, systemInstruction);
      if (text) {
        storageService.logAIResponse("IA_1_OPENROUTER", Date.now() - start);
        return { 
          text, 
          source: "Nexus Alpha (IA 1 - Réflexion)", 
          isFallback: false,
          status: 'SUCCESS'
        };
      }
    } catch (e: any) {
      console.error("Échec IA 1:", e.message);
      storageService.logAIError("IA_1_OPENROUTER", e.message);
    }

    // TENTATIVE 2 : BASCULEMENT VERS GEMINI (FALLBACK)
    try {
      const text = await aiService.fetchGeminiFallback(messages, systemInstruction);
      storageService.logAIResponse("GEMINI_BACKUP", Date.now() - start);
      return { 
        text, 
        source: "Relais Gemini (Sécurité)", 
        isFallback: true,
        status: 'RELAY'
      };
    } catch (e: any) {
      storageService.logAIError("GEMINI_BACKUP", e.message);
      return { 
        text: "ALERTE : Tous les canaux de transmission sont rompus. Contactez l'administrateur Astarté.", 
        source: "NEURAL_BLACKOUT", 
        isFallback: true,
        status: 'CRITICAL'
      };
    }
  }
};

