    try {
      const text = await aiService.fetchPrimaryAI(messages, systemInstruction);
      const end = Date.now();
      storageService.logAIResponse("IA_1_OPENROUTER", end - start);
      return { 
        text, 
        source: "Nexus Alpha (IA 1)", 
        isFallback: false,
        status: 'SUCCESS',
        responseTime: end - start
      };
    } catch (e: any) {
      console.warn("IA 1 instable ou lente. Activation du protocole de secours Gemini...");
      storageService.logAIError("IA_1_OPENROUTER", e.message);
    }

    // PHASE 2 : BASCULEMENT INSTANTANÉ
