// app/api/chat/route.js

export async function POST(request) {
  try {
    const { message } = await request.json();

    if (!message) {
      return new Response(JSON.stringify({ 
        response: 'Veuillez entrer un message.' 
      }), {
        status: 400,
        headers: { 'Content-Type': 'application/json' }
      });
    }

    // Récupérer toutes les clés API depuis les variables d'environnement
    const apiKeys = [
      process.env.API_KEY_1,
      process.env.API_KEY_2,
      process.env.API_KEY_3,
      process.env.API_KEY_4,
    ].filter(key => key && key.trim() !== '');

    if (apiKeys.length === 0) {
      return new Response(JSON.stringify({ 
        response: 'Configuration API manquante.' 
      }), {
        status: 500,
        headers: { 'Content-Type': 'application/json' }
      });
    }

    // Créer les requêtes pour TOUTES les IA en parallèle
    const requests = apiKeys.map((apiKey, index) => 
      callOpenRouterAPI(apiKey, message, index + 1)
    );

    // Utiliser Promise.any pour prendre la première réponse qui réussit
    const fastestResponse = await Promise.any(requests);

    return new Response(JSON.stringify({ 
      response: fastestResponse,
      source: `IA-${fastestResponse.source}` // Optionnel: savoir quelle IA a répondu
    }), {
      status: 200,
      headers: { 'Content-Type': 'application/json' }
    });

  } catch (error) {
    console.error('Erreur globale:', error);

    // En cas d'échec de toutes les IA, utiliser une réponse de secours
    return new Response(JSON.stringify({ 
      response: 'Je suis actuellement en maintenance. Veuillez réessayer dans quelques instants.',
      error: true
    }), {
      status: 200, // On retourne 200 pour ne pas casser le frontend
      headers: { 'Content-Type': 'application/json' }
    });
  }
}

// Fonction pour appeler OpenRouter avec une clé spécifique
async function callOpenRouterAPI(apiKey, message, apiNumber) {
  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), 10000); // Timeout de 10 secondes

  try {
    const response = await fetch('https://openrouter.ai/api/v1/chat/completions', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${apiKey}`,
        'Content-Type': 'application/json',
        'HTTP-Referer': 'https://success-polaris-mowa.vercel.app/',
        'X-Title': 'Polaris Success'
      },
      body: JSON.stringify({
        // Utiliser des modèles gratuits ou peu coûteux
        model: getModelForAPI(apiNumber), // Fonction pour choisir le modèle
        messages: [
          {
            role: 'system',
            content: `Vous êtes un assistant IA pour le site "Polaris Success". 
                     Vous aidez les utilisateurs avec des conseils en développement personnel, 
                     productivité, et réussite. Soyez concis, positif et encourageant.
                     Répondez en français sauf si l'utilisateur demande dans une autre langue.`
          },
          {
            role: 'user',
            content: message
          }
        ],
        max_tokens: 500,
        temperature: 0.7
      }),
      signal: controller.signal
    });

    clearTimeout(timeoutId);

    if (!response.ok) {
      throw new Error(`API ${apiNumber} échouée: ${response.status}`);
    }

    const data = await response.json();

    if (data.choices && data.choices[0]) {
      return {
        content: data.choices[0].message.content,
        source: apiNumber
      };
    } else {
      throw new Error(`API ${apiNumber}: réponse invalide`);
    }

  } catch (error) {
    clearTimeout(timeoutId);
    throw error; // Propager l'erreur pour Promise.any
  }
}

// Fonction pour attribuer des modèles différents à chaque API
function getModelForAPI(apiNumber) {
  const models = {
    1: 'google/gemini-pro',        // Gratuit ou peu coûteux
    2: 'mistralai/mistral-7b-instruct', // Gratuit
    3: 'huggingfaceh4/zephyr-7b-beta', // Gratuit
    4: 'meta-llama/llama-3-8b-instruct' // Gratuit
  };

  return models[apiNumber] || 'google/gemini-pro';
}

