import React, { useState, useRef, useEffect } from 'react';
import { aiService, AIProviderResponse } from '../services/aiService.ts';
import { Document, ChatMessage as TypeChatMessage } from '../types.ts';

interface ChatWidgetProps {
  documents: Document[];
}

interface WidgetMessage {
  role: 'assistant' | 'user';
  content: string;
  source?: string;
  error?: boolean;
}

export default function ChatWidget({ documents }: ChatWidgetProps) {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<WidgetMessage[]>([
    { role: 'assistant', content: "Bonjour ! Je suis votre assistant Polaris. Comment puis-je vous aider aujourd'hui ?" }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Faire défiler automatiquement vers le dernier message
  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isLoading]);

  const sendMessage = async () => {
    if (!input.trim() || isLoading) return;

    const userMessage: WidgetMessage = { role: 'user', content: input };
    setMessages(prev => [...prev, userMessage]);
    const currentInput = input;
    setInput('');
    setIsLoading(true);

    try {
      // Conversion des messages pour le service IA
      const history: TypeChatMessage[] = messages.map(m => ({
        role: m.role === 'assistant' ? 'model' : 'user',
        text: m.content,
        timestamp: ''
      }));

      const response: AIProviderResponse = await aiService.processMessage(
        [...history, { role: 'user', text: currentInput, timestamp: '' }],
        documents
      );

      setMessages(prev => [...prev, { 
        role: 'assistant', 
        content: response.text,
        source: response.source ? ` (IA-${response.source})` : ''
      }]);
    } catch (error) {
      console.error('Erreur Nexus:', error);
      setMessages(prev => [...prev, { 
        role: 'assistant', 
        content: "Désolé, je rencontre des difficultés techniques avec le Nexus. Veuillez réessayer.",
        error: true
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  };

  return (
    <>
      {/* Bouton flottant */}
      <button
        onClick={() => setIsOpen(true)}
        className="chat-toggle-btn group"
        style={{
          position: 'fixed',
          bottom: '24px',
          right: '24px',
          background: 'linear-gradient(135deg, #00d4ff 0%, #3b82f6 100%)',
          color: '#020617',
          padding: '16px 28px',
          borderRadius: '50px',
          border: 'none',
          cursor: 'pointer',
          zIndex: 8000,
          boxShadow: '0 10px 30px rgba(0, 212, 255, 0.3)',
          fontSize: '14px',
          fontWeight: '900',
          display: 'flex',
          alignItems: 'center',
          gap: '10px',
          transition: 'all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275)',
          textTransform: 'uppercase',
          letterSpacing: '0.1em'
        }}
      >
        <div className="w-6 h-6 bg-black/10 rounded-full flex items-center justify-center">
            <i className="fas fa-brain text-xs"></i>
        </div>
        Assistant IA
      </button>

      {/* Modal du chat */}
      {isOpen && (
        <div 
          className="chat-container animate-in slide-in-from-bottom-5 duration-300"
          style={{
            position: 'fixed',
            bottom: '95px',
            right: '24px',
            width: 'calc(100vw - 48px)',
            maxWidth: '420px',
            height: 'min(700px, 80vh)',
            background: 'white',
            borderRadius: '32px',
            boxShadow: '0 25px 70px rgba(0,0,0,0.4)',
            zIndex: 8001,
            display: 'flex',
            flexDirection: 'column',
            overflow: 'hidden',
            border: '1px solid rgba(0,0,0,0.05)'
          }}
        >
          {/* En-tête */}
          <div style={{
            background: 'linear-gradient(135deg, #020617 0%, #0f172a 100%)',
            color: 'white',
            padding: '24px',
            display: 'flex',
            justifyContent: 'space-between',
            alignItems: 'center',
            borderBottom: '1px solid rgba(255,255,255,0.05)'
          }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                <div style={{ width: '40px', height: '40px', background: 'rgba(0,212,255,0.1)', border: '1px solid rgba(0,212,255,0.2)', borderRadius: '14px', display: 'flex', alignItems: 'center', justifyCenter: 'center' }}>
                    <i className="fas fa-atom text-cyan-400 m-auto text-sm"></i>
                </div>
                <div>
                  <h3 style={{ margin: 0, fontSize: '15px', fontWeight: '900', textTransform: 'uppercase', letterSpacing: '0.05em' }}>Assistant Polaris</h3>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '6px', marginTop: '2px' }}>
                    <div style={{ width: '6px', height: '6px', borderRadius: '50%', background: '#10b981', boxShadow: '0 0 5px #10b981' }}></div>
                    <p style={{ margin: 0, fontSize: '10px', opacity: 0.6, fontWeight: '700', textTransform: 'uppercase' }}>
                        4 IA en parallèle • Nexus Actif
                    </p>
                  </div>
                </div>
            </div>
            <button 
              onClick={() => setIsOpen(false)}
              style={{ 
                background: 'rgba(255,255,255,0.05)', 
                border: 'none', 
