                justifyContent: 'center',
                fontSize: '14px',
                transition: 'all 0.2s'
              }}
              onMouseEnter={(e) => e.currentTarget.style.background = 'rgba(255,255,255,0.1)'}
              onMouseLeave={(e) => e.currentTarget.style.background = 'rgba(255,255,255,0.05)'}
            >
              <i className="fas fa-times"></i>
            </button>
          </div>

          {/* Messages */}
          <div style={{ 
            flex: 1, 
            overflowY: 'auto', 
            padding: '24px',
            background: '#f8fafc',
            display: 'flex',
            flexDirection: 'column',
            gap: '16px'
          }}>
            {messages.map((msg, index) => (
              <div
                key={index}
                style={{
                  padding: '16px 20px',
                  borderRadius: msg.role === 'user' ? '24px 24px 4px 24px' : '24px 24px 24px 4px',
                  background: msg.role === 'user' 
                    ? 'linear-gradient(135deg, #00d4ff 0%, #3b82f6 100%)' 
                    : '#ffffff',
                  color: msg.role === 'user' ? '#020617' : '#1e293b',
                  alignSelf: msg.role === 'user' ? 'flex-end' : 'flex-start',
                  maxWidth: '85%',
                  boxShadow: msg.role === 'user' 
                    ? '0 10px 20px rgba(0, 212, 255, 0.2)'
                    : '0 4px 15px rgba(0,0,0,0.04)',
                  border: msg.error ? '1px solid #fee2e2' : 'none',
                  fontSize: '14px',
                  lineHeight: '1.6',
                  fontWeight: msg.role === 'user' ? '700' : '500'
                }}
              >
                {msg.content}
                {msg.source && (
                  <div style={{ 
                    fontSize: '9px', 
                    opacity: 0.5, 
                    marginTop: '8px',
                    fontWeight: '900',
                    textTransform: 'uppercase',
                    textAlign: 'right'
                  }}>
                    {msg.source}
                  </div>
                )}
              </div>
            ))}

            {isLoading && (
              <div style={{
                padding: '16px 20px',
                borderRadius: '24px 24px 24px 4px',
                background: '#ffffff',
                alignSelf: 'flex-start',
                maxWidth: '85%',
                boxShadow: '0 4px 15px rgba(0,0,0,0.04)'
              }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                  <div className="flex gap-1">
                    <div className="w-1.5 h-1.5 bg-cyan-500 rounded-full animate-bounce"></div>
                    <div className="w-1.5 h-1.5 bg-cyan-500 rounded-full animate-bounce delay-100"></div>
                    <div className="w-1.5 h-1.5 bg-cyan-500 rounded-full animate-bounce delay-200"></div>
                  </div>
                  <span style={{ fontSize: '11px', color: '#64748b', fontWeight: '700', textTransform: 'uppercase', letterSpacing: '0.05em' }}>
                    Course de flux...
                  </span>
                </div>
              </div>
            )}

            <div ref={messagesEndRef} />
          </div>

          {/* Input */}
          <div style={{ 
            padding: '24px', 
            borderTop: '1px solid #f1f5f9',
            background: 'white'
          }}>
            <div style={{ display: 'flex', gap: '12px', alignItems: 'flex-end' }}>
              <textarea
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={handleKeyPress}
                placeholder="Posez votre question au Nexus..."
                rows={1}
                style={{
                  flex: 1,
                  padding: '14px 20px',
                  background: '#f8fafc',
                  border: '1px solid #e2e8f0',
                  borderRadius: '20px',
                  fontSize: '14px',
                  resize: 'none',
                  outline: 'none',
                  fontFamily: 'inherit',
                  minHeight: '48px',
                  maxHeight: '120px',
                  fontWeight: '500',
                  color: '#1e293b'
                }}
              />
              <button
                onClick={sendMessage}
                disabled={isLoading || !input.trim()}
                style={{
                  width: '48px',
                  height: '48px',
                  background: input.trim() && !isLoading
                    ? 'linear-gradient(135deg, #00d4ff 0%, #3b82f6 100%)'
                    : '#f1f5f9',
                  color: input.trim() && !isLoading ? '#020617' : '#94a3b8',
                  border: 'none',
                  borderRadius: '16px',
                  cursor: input.trim() && !isLoading ? 'pointer' : 'not-allowed',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  transition: 'all 0.3s ease',
                  flexShrink: 0
                }}
              >
                <i className="fas fa-paper-plane text-sm"></i>
