            >
              <i className="fas fa-times"></i>
            </button>
          </div>

          {/* Messages */}
          <div style={{ 
            flex: 1, 
            overflowY: 'auto', 
            padding: '24px',
            background: '#f8fafc',
            display: 'flex',
            flexDirection: 'column',
            gap: '16px'
          }}>
            {messages.map((msg, index) => (
              <div
                key={index}
                style={{
                  padding: '16px 20px',
                  borderRadius: msg.role === 'user' ? '24px 24px 4px 24px' : '24px 24px 24px 4px',
                  background: msg.role === 'user' 
                    ? 'linear-gradient(135deg, #00d4ff 0%, #3b82f6 100%)' 
                    : '#ffffff',
                  color: msg.role === 'user' ? '#020617' : '#1e293b',
                  alignSelf: msg.role === 'user' ? 'flex-end' : 'flex-start',
                  maxWidth: '85%',
                  boxShadow: msg.role === 'user' 
                    ? '0 10px 20px rgba(0, 212, 255, 0.2)'
                    : '0 4px 15px rgba(0,0,0,0.04)',
                  border: msg.error ? '1px solid #fee2e2' : 'none',
                  fontSize: '14px',
                  lineHeight: '1.6',
                  fontWeight: msg.role === 'user' ? '700' : '500'
                }}
              >
                {msg.content}
                {msg.source && (
                  <div style={{ 
