                    fontWeight: '900',
                    textTransform: 'uppercase',
                    textAlign: 'right'
                  }}>
                    {msg.source}
                  </div>
                )}
              </div>
            ))}

            {isLoading && (
              <div style={{
                padding: '16px 20px',
                borderRadius: '24px 24px 24px 4px',
