              }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                  <div className="flex gap-1">
                    <div className="w-1.5 h-1.5 bg-cyan-500 rounded-full animate-bounce"></div>
                    <div className="w-1.5 h-1.5 bg-cyan-500 rounded-full animate-bounce delay-100"></div>
                    <div className="w-1.5 h-1.5 bg-cyan-500 rounded-full animate-bounce delay-200"></div>
                  </div>
                  <span style={{ fontSize: '11px', color: '#64748b', fontWeight: '700', textTransform: 'uppercase', letterSpacing: '0.05em' }}>
                    Course de flux...
                  </span>
                </div>
              </div>
            )}

            <div ref={messagesEndRef} />
          </div>

          {/* Input Area with Custom Editor */}
          <div style={{ 
            padding: '24px', 
            borderTop: '1px solid #f1f5f9',
            background: 'white'
          }}>
            <div style={{ display: 'flex', gap: '12px', alignItems: 'flex-end' }}>
              <div style={{ position: 'relative', flex: 1 }}>
                <div
                  ref={editorRef}
                  contentEditable
                  id="polaris-custom-editor"
                  className="polaris-text-editor"
                  style={{
                    minHeight: '48px',
                    maxHeight: '150px',
                    padding: '12px 20px',
                    border: '1px solid #e2e8f0',
                    borderRadius: '24px',
                    fontSize: '14px',
                    background: '#f8fafc',
                    outline: 'none',
                    overflowY: 'auto',
                    whiteSpace: 'pre-wrap',
                    wordBreak: 'break-word',
                    fontWeight: '500',
                    color: '#1e293b'
                  }}
                  onInput={(e) => setInput(e.currentTarget.textContent || '')}
                  onKeyDown={(e) => {
                    if (e.key === 'Enter' && !e.shiftKey) {
                      e.preventDefault();
                      sendMessage();
                    }
                  }}
                  data-gramm="false"
                  data-gramm_editor="false"
                  data-enable-grammarly="false"
                  spellCheck="false"
                  autoComplete="off"
