import React, { useState, useRef, useEffect } from 'react';
import { aiService, AIProviderResponse } from '../services/aiService.ts';
import { Document, ChatMessage as TypeChatMessage } from '../types.ts';

interface ChatWidgetProps {
  documents: Document[];
}

interface WidgetMessage {
  role: 'assistant' | 'user';
  content: string;
  source?: string;
  error?: boolean;
}

export default function ChatWidget({ documents }: ChatWidgetProps) {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<WidgetMessage[]>([
    { role: 'assistant', content: "Bonjour ! Je suis votre assistant Polaris sécurisé. Environnement isolé activé." }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const editorRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isLoading]);

  const sendMessage = async () => {
    if (!input.trim() || isLoading) return;

    const currentInput = input;
    const userMessage: WidgetMessage = { role: 'user', content: currentInput };
    setMessages(prev => [...prev, userMessage]);

    setInput('');
    if (editorRef.current) {
        editorRef.current.textContent = '';
    }

    setIsLoading(true);

    try {
      const history: TypeChatMessage[] = messages.map(m => ({
        role: m.role === 'assistant' ? 'model' : 'user',
        text: m.content,
        timestamp: ''
      }));

      const response: AIProviderResponse = await aiService.processMessage(
        [...history, { role: 'user', text: currentInput, timestamp: '' }],
        documents
      );

      setMessages(prev => [...prev, { 
        role: 'assistant', 
        content: response.text,
        source: response.source ? ` (Nexus Isolé: ${response.source})` : ''
      }]);
    } catch (error) {
      setMessages(prev => [...prev, { 
        role: 'assistant', 
        content: "Désolé, le Nexus est temporairement indisponible.",
        error: true
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <>
      {/* Bouton flottant "Sécurisé" */}
      <button
        onClick={() => setIsOpen(true)}
        style={{
          position: 'fixed',
          bottom: '24px',
          right: '24px',
          background: 'linear-gradient(135deg, #10b981 0%, #059669 100%)',
          color: 'white',
          padding: '16px 28px',
          borderRadius: '50px',
          border: 'none',
          cursor: 'pointer',
          zIndex: 8000,
          boxShadow: '0 10px 30px rgba(16, 185, 129, 0.3)',
          fontSize: '14px',
          fontWeight: '900',
          display: 'flex',
          alignItems: 'center',
          gap: '10px',
          textTransform: 'uppercase',
          letterSpacing: '0.1em'
        }}
      >
        <span style={{ fontSize: '18px' }}>🔒</span>
        Assistant Sécurisé
      </button>

      {/* Modal du chat isolé */}
      {isOpen && (
        <div 
          className="animate-in slide-in-from-bottom-5 duration-300"
          style={{
            position: 'fixed',
            bottom: '95px',
            right: '24px',
            width: 'calc(100vw - 48px)',
            maxWidth: '450px',
            height: 'min(700px, 85vh)',
            background: 'white',
            borderRadius: '24px',
            boxShadow: '0 25px 70px rgba(0,0,0,0.4)',
            zIndex: 8001,
            display: 'flex',
            flexDirection: 'column',
            overflow: 'hidden',
            border: '2px solid #10b981'
          }}
        >
          {/* En-tête Sécurisé */}
          <div style={{
            background: 'linear-gradient(135deg, #064e3b 0%, #022c22 100%)',
            color: 'white',
            padding: '24px',
            display: 'flex',
            justifyContent: 'space-between',
            alignItems: 'center'
          }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                <div style={{ width: '40px', height: '40px', background: 'rgba(16,185,129,0.1)', border: '1px solid rgba(16,185,129,0.3)', borderRadius: '12px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                    <i className="fas fa-shield-alt text-emerald-400"></i>
                </div>
                <div>
                  <h3 style={{ margin: 0, fontSize: '14px', fontWeight: '900', textTransform: 'uppercase' }}>Polaris AI Private</h3>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '6px', marginTop: '2px' }}>
                    <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></div>
                    <span style={{ fontSize: '9px', opacity: 0.7, fontWeight: '700', textTransform: 'uppercase' }}>Environnement Isolé • No-Sync</span>
                  </div>
                </div>
            </div>
            <button 
              onClick={() => setIsOpen(false)}
              style={{ background: 'none', border: 'none', color: 'white', cursor: 'pointer', fontSize: '20px' }}
            >
              <i className="fas fa-times"></i>
            </button>
          </div>

          {/* Zone de Messages */}
          <div style={{ flex: 1, overflowY: 'auto', padding: '20px', background: '#f9fafb', display: 'flex', flexDirection: 'column', gap: '12px' }}>
            {messages.map((msg, index) => (
              <div
                key={index}
                style={{
                  padding: '12px 16px',
                  borderRadius: msg.role === 'user' ? '16px 16px 4px 16px' : '16px 16px 16px 4px',
                  background: msg.role === 'user' ? '#10b981' : 'white',
                  color: msg.role === 'user' ? 'white' : '#1f2937',
                  alignSelf: msg.role === 'user' ? 'flex-end' : 'flex-start',
                  maxWidth: '85%',
                  boxShadow: '0 2px 8px rgba(0,0,0,0.05)',
                  fontSize: '13px',
                  lineHeight: '1.5'
                }}
              >
                {msg.content}
                {msg.source && <div style={{ fontSize: '8px', opacity: 0.5, marginTop: '5px', textAlign: 'right' }}>{msg.source}</div>}
              </div>
            ))}
            {isLoading && <div className="text-[10px] text-emerald-600 font-bold animate-pulse px-4">Analyse du Nexus...</div>}
            <div ref={messagesEndRef} />
          </div>

          {/* Éditeur ContentEditable Sécurisé */}
          <div style={{ padding: '20px', borderTop: '1px solid #e5e7eb', background: 'white' }}>
            <div style={{ position: 'relative' }}>
              <div
                ref={editorRef}
                contentEditable
                id="polaris-custom-editor"
                style={{
                  minHeight: '48px',
                  maxHeight: '150px',
                  padding: '12px 16px',
                  border: '1px solid #d1d5db',
                  borderRadius: '16px',
                  fontSize: '14px',
                  background: '#ffffff',
                  outline: 'none',
                  overflowY: 'auto',
                  whiteSpace: 'pre-wrap',
                  wordBreak: 'break-word',
                  color: '#374151'
                }}
                onInput={(e) => setInput(e.currentTarget.textContent || '')}
                onKeyDown={(e) => {
                  if (e.key === 'Enter' && !e.shiftKey) {
                    e.preventDefault();
                    sendMessage();
                  }
                }}
                data-gramm="false"
                data-gramm_editor="false"
                data-enable-grammarly="false"
                spellCheck="false"
                autoComplete="off"
                autoCorrect="off"
                autoCapitalize="off"
              />
              {!input && (
                <div style={{ position: 'absolute', top: '12px', left: '16px', color: '#9ca3af', pointerEvents: 'none', fontSize: '14px' }}>
                  Posez votre question...
                </div>
              )}
            </div>

            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '12px' }}>
                <p style={{ fontSize: '9px', color: '#9ca3af', fontWeight: '700', textTransform: 'uppercase' }}>Sécurité : Chiffrement Polaris</p>
                <button
                    onClick={sendMessage}
                    disabled={isLoading || !input.trim()}
                    style={{
                        padding: '8px 16px',
                        background: '#10b981',
                        color: 'white',
                        borderRadius: '10px',
                        border: 'none',
                        fontSize: '11px',
                        fontWeight: 'bold',
                        cursor: 'pointer',
                        opacity: (isLoading || !input.trim()) ? 0.5 : 1
                    }}
                >
                    ENVOYER
                </button>
            </div>
          </div>
        </div>
      )}
    </>
  );
}

