{
  "rewrites": [
    {
      "source": "/api/:path*",
      "destination": "/api/:path*"
    },
    {
      "source": "/(.*)",
      "destination": "/index.html"
    }
  ],
  "functions": {
    "api/chat.js": {
      "maxDuration": 10
    }
  }
}

ÉTAPE 3 : Créez la fonction serverless CORRECTEMENT

Créez le dossier : api/chat.js (à la racine, PAS dans src/ ou public/)
javascript

// api/chat.js
export default async function handler(request, response) {
  // Ne permettre que les requêtes POST
  if (request.method !== 'POST') {
    return response.status(405).json({ 
      error: 'Méthode non autorisée. Utilisez POST.' 
    });
  }

  try {
    const { message } = await request.json();

    if (!message || message.trim() === '') {
      return response.status(400).json({ 
        error: 'Message requis' 
      });
    }

    // Récupérer les clés API depuis les variables d'environnement Vercel
    const apiKeys = [
      process.env.API_KEY_1,
      process.env.API_KEY_2,
      process.env.API_KEY_3,
      process.env.API_KEY_4
    ].filter(key => key && key.trim() !== '');

    if (apiKeys.length === 0) {
      console.error('❌ Aucune clé API trouvée dans les variables d\'environnement');
      return response.status(500).json({ 
        response: 'ERREUR CRITIQUE : Configuration système indisponible' 
      });
    }

    console.log(`✅ ${apiKeys.length} clés API disponibles`);

    // Utiliser la première clé valide
    const apiKey = apiKeys[0];
    const maskedKey = apiKey.substring(0, 8) + '...' + apiKey.substring(apiKey.length - 4);
    console.log(`🔑 Utilisation de la clé: ${maskedKey}`);

    // Appeler OpenRouter
    const openRouterResponse = await fetch('https://openrouter.ai/api/v1/chat/completions', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${apiKey}`,
        'Content-Type': 'application/json',
        'HTTP-Referer': 'https://success-polaris-mowa.vercel.app',
        'X-Title': 'Success Polaris'
      },
      body: JSON.stringify({
        model: 'google/gemini-pro',
        messages: [
          {
            role: 'system',
            content: `Tu es Nexus Polaris, assistant IA de Success Polaris.
            Tu aides les étudiants pour le BAC et le développement personnel.
            Sois encourageant, positif et précis.
            Réponds toujours en français.`
          },
          {
            role: 'user',
            content: message
          }
        ],
        max_tokens: 500
      })
    });

    if (!openRouterResponse.ok) {
      const errorText = await openRouterResponse.text();
      console.error('❌ Erreur OpenRouter:', openRouterResponse.status, errorText);

      return response.status(200).json({ 
        response: 'SYSTÈME POLARIS : Connexion sécurisée en restauration... Veuillez réessayer.' 
      });
    }

    const data = await openRouterResponse.json();

    if (data.choices && data.choices[0] && data.choices[0].message) {
      return response.status(200).json({
        response: data.choices[0].message.content,
        source: 'NEXUS-POLARIS',
        status: 'ACTIF'
      });
    } else {
      throw new Error('Structure de réponse invalide');
    }

  } catch (error) {
    console.error('💥 Erreur dans /api/chat:', error);

    return response.status(200).json({ 
      response: 'NEXUS POLARIS : Système en maintenance. Réessayez dans quelques instants.',
      error: true,
      status: 'MAINTENANCE'
    });
  }
}

